178	// ---------------------------------------------------------------------------
179	// buildPromptContext — public builder
180	// ---------------------------------------------------------------------------
181	
182	/**
183	 * Builds a PromptContext ready for assemblePrompt().
184	 *
185	 * The returned context is fully populated: every standard template variable
186	 * has a value. Optional content (architecture.md, handoff.json, etc.) uses
187	 * "" when the file is absent.
188	 *
189	 * AC-4/RC-3: item.data is parsed as an opaque blob and stored whole under
190	 * ctx["item"]. The builder does not access any named fields within item.data.
191	 *
192	 * @throws {SyntaxError} if item.data is not valid JSON (caller should treat
193	 *   this as a configuration error — the item manifest must contain valid JSON).
194	 */
195	export async function buildPromptContext(inputs: PromptContextInputs): Promise<PromptContext> {
196	  const {
197	    workflow,
198	    stage,
199	    item,
200	    worktreePath,
201	    git,
202	    userInjectedContext = '',
203	  } = inputs;
204	
205	  // ---------------------------------------------------------------------------
206	  // Read architecture.md (or "")
207	  // ---------------------------------------------------------------------------
208	  const archPath = inputs.architectureMdPath ?? path.join(worktreePath, 'architecture.md');
209	  const architecture_md = readFileOrEmpty(archPath);
210	
211	  // ---------------------------------------------------------------------------
212	  // Call git.logRecent(20) for {{git_log_recent}}
213	  // ---------------------------------------------------------------------------
214	  const git_log_recent = await git.logRecent(20);
215	
216	  // ---------------------------------------------------------------------------
217	  // Base context — available in all phases
218	  // ---------------------------------------------------------------------------
219	  const ctx: PromptContext = {
220	    workflow_name: workflow.name,
221	    stage_id: stage.id,
222	    architecture_md,
223	    git_log_recent,
224	    user_injected_context: userInjectedContext,
225	  };
226	
227	  // ---------------------------------------------------------------------------
228	  // Per-item phase variables (stage.run === 'per-item' with an item present)
229	  // ---------------------------------------------------------------------------
230	  if (stage.run === 'per-item' && item !== undefined) {
231	    // AC-4/RC-3: parse item.data as an opaque blob — no named field access.
232	    // The entire parsed object is stored under "item"; the template engine
233	    // handles field access via dot traversal ({{item.description}}, etc.).
234	    const parsedItemData = JSON.parse(item.data) as Record<string, unknown>;
235	
236	    // Project harness-level state (Issue 3). These are the columns from the
237	    // items table, NOT from item.data — the distinction is important (AC-1).
238	    const item_state: ItemStateProjection = {
239	      status: item.status,
240	      current_phase: item.current_phase,
241	      retry_count: item.retry_count,
242	      blocked_reason: item.blocked_reason,
243	    };
244	
245	    // Read progress.md (or "")
246	    const progressPath = inputs.progressMdPath ?? path.join(worktreePath, 'progress.md');
247	    const progress_md = readFileOrEmpty(progressPath);
248	
249	    // Read handoff.json and serialize entries (AC-6: {{handoff}})
250	    const handoffPath = inputs.handoffPath ?? path.join(worktreePath, 'handoff.json');
251	    const handoff = readHandoffEntries(handoffPath);
252	
253	    // Compute recent_diff if refs are provided (or "")
254	    let recent_diff = '';
255	    if (inputs.diffFrom) {
256	      const diffTo = inputs.diffTo ?? 'HEAD';
257	      recent_diff = await git.diffRange(inputs.diffFrom, diffTo);
258	    }
259	
260	    Object.assign(ctx, {
261	      item_id: item.id,
262	      item: parsedItemData,
263	      item_state: item_state as unknown as Record<string, unknown>,
264	      progress_md,
265	      handoff,
266	      recent_diff,
267	    });
268	  }
269	
270	  return ctx;
271	}
