274	// Private helpers
275	// ---------------------------------------------------------------------------
276	
277	/**
278	 * Reads a UTF-8 text file and returns its contents, or "" if the file does
279	 * not exist. Other errors (permission denied, I/O error) are re-thrown.
280	 */
281	function readFileOrEmpty(filePath: string): string {
282	  try {
283	    return fs.readFileSync(filePath, 'utf8');
284	  } catch (err: unknown) {
285	    const e = err as NodeJS.ErrnoException;
286	    if (e.code === 'ENOENT') {
287	      return '';
288	    }
289	    throw err;
290	  }
291	}
292	
293	/**
294	 * Reads handoff.json and returns the entries array as a pretty-printed JSON
295	 * string (AC-6: {{handoff}} variable).
296	 *
297	 * The "most-recent handoff entries" are all entries from the current
298	 * handoff.json file (the file is rewritten each workflow run, so reading it
299	 * gives the up-to-date state).
300	 *
301	 * Returns "" if the file is absent (no handoff entries yet).
302	 * Returns "[]" if the file exists but has no entries array.
303	 *
304	 * @throws {SyntaxError} if the file exists but is not valid JSON.
305	 */
306	function readHandoffEntries(filePath: string): string {
307	  const raw = readFileOrEmpty(filePath);
308	  if (raw === '') {
309	    return '';
310	  }
311	  const parsed = JSON.parse(raw) as HandoffFile;
312	  const entries = parsed.entries ?? [];
313	  return JSON.stringify(entries, null, 2);
314	}
