1	/**
2	 * yoke start — spawn the Yoke pipeline engine.
3	 *
4	 * 1. Loads and validates .yoke.yml via loadConfig (exits non-zero on failure).
5	 * 2. Opens the SQLite database under .yoke/yoke.db; runs forward-only migrations.
6	 * 3. Calls listenServer on 127.0.0.1 at the configured port (default 7777).
7	 * 4. Logs the server URL.
8	 * 5. Writes .yoke/server.json so that yoke status / yoke cancel can discover
9	 *    the running instance.
10	 * 6. Keeps the process alive (the server drives the event loop).
11	 *
12	 * Acceptance criteria:
13	 *   AC: Spawns the pipeline engine and logs the server URL.
14	 *   AC: Exits non-zero if config validation fails.
15	 *   RC: Handles ECONNREFUSED with a clear message (N/A here — start IS the server).
16	 */
17	
18	import fs from 'node:fs';
19	import path from 'node:path';
20	import { fileURLToPath } from 'node:url';
21	import type { Command } from 'commander';
22	import { loadConfig } from '../server/config/loader.js';
23	import { ConfigLoadError } from '../server/config/errors.js';
24	import { openDbPool, type DbPool } from '../server/storage/db.js';
25	import { applyMigrations } from '../server/storage/migrate.js';
26	import { listenServer } from '../server/api/server.js';
27	import type { FastifyInstance } from 'fastify';
28	
29	// ---------------------------------------------------------------------------
30	// Helpers
31	// ---------------------------------------------------------------------------
32	
33	/** Path to the migrations directory, resolved relative to this source file. */
34	function migrationsDir(): string {
35	  const here = path.dirname(fileURLToPath(import.meta.url));
36	  return path.resolve(here, '../server/storage/migrations');
37	}
38	
39	// ---------------------------------------------------------------------------
40	// Public API (exported for testing)
41	// ---------------------------------------------------------------------------
42	
43	export interface StartOptions {
44	  /** Path to the .yoke.yml config file. Default: <cwd>/.yoke.yml */
45	  configPath?: string;
46	  /** Server port. Default: 7777 */
47	  port?: number;
48	}
49	
50	export interface StartHandle {
51	  url: string;
52	  db: DbPool;
53	  fastify: FastifyInstance;
54	  /** Clean shutdown: closes db + fastify. */
55	  close(): Promise<void>;
56	}
57	
58	/**
59	 * Validate config, open DB, run migrations, start Fastify, return a handle.
60	 * Throws on config validation failure (caller should exit non-zero).
61	 * Exported for integration tests.
62	 */
63	export async function startServer(opts: StartOptions = {}): Promise<StartHandle> {
64	  const configPath = opts.configPath ?? path.join(process.cwd(), '.yoke.yml');
65	  const port = opts.port ?? 7777;
66	
67	  // Load + validate config — throws ConfigLoadError on failure.
68	  const config = loadConfig(configPath);
69	
70	  // Database lives under .yoke/ in the config directory.
71	  const yokeDir = path.join(config.configDir, '.yoke');
72	  fs.mkdirSync(yokeDir, { recursive: true });
73	  const dbPath = path.join(yokeDir, 'yoke.db');
74	
75	  const db = openDbPool(dbPath);
76	  applyMigrations(db.writer, migrationsDir());
77	
78	  // Start server.
79	  const fastify = await listenServer(db, { port });
80	
81	  const addr = fastify.server.address();
82	  const actualPort = typeof addr === 'object' && addr !== null ? addr.port : port;
83	  const url = `http://127.0.0.1:${actualPort}`;
84	
85	  // Write server discovery file.
86	  const serverJson = path.join(yokeDir, 'server.json');
87	  fs.writeFileSync(serverJson, JSON.stringify({ url, pid: process.pid }), 'utf8');
88	
89	  return {
90	    url,
91	    db,
92	    fastify,
93	    async close() {
94	      await fastify.close();
95	      db.close();
96	      // Remove discovery file on clean shutdown.
97	      try {
98	        fs.unlinkSync(serverJson);
99	      } catch {
100	        // Not fatal if already removed.
101	      }
102	    },
103	  };
104	}
105	
106	// ---------------------------------------------------------------------------
107	// Commander registration
108	// ---------------------------------------------------------------------------
109	
110	export function register(program: Command): void {
111	  program
112	    .command('start')
113	    .description('Start the Yoke pipeline engine')
114	    .option('-c, --config <path>', 'Path to .yoke.yml', '.yoke.yml')
115	    .option('-p, --port <number>', 'Server port', '7777')
116	    .action(async (opts: { config: string; port: string }) => {
117	      const configPath = path.resolve(opts.config);
118	      const port = parseInt(opts.port, 10);
119	
120	      let handle: StartHandle;
121	      try {
122	        handle = await startServer({ configPath, port });
123	      } catch (err) {
124	        if (err instanceof ConfigLoadError) {
125	          console.error(`Configuration error: ${err.message}`);
126	          process.exit(1);
127	        }
128	        throw err;
129	      }
130	
131	      console.log(`Yoke server running at ${handle.url}`);
132	
133	      // Keep process alive. SIGINT / SIGTERM → graceful shutdown.
134	      async function shutdown(signal: string): Promise<never> {
135	        console.log(`\n${signal} received — shutting down...`);
136	        await handle.close();
137	        process.exit(0);
138	      }
139	
140	      process.on('SIGINT', () => void shutdown('SIGINT'));
141	      process.on('SIGTERM', () => void shutdown('SIGTERM'));
142	    });
143	}
