1	/**
2	 * Worktree Manager — creates, bootstraps, and cleans up git worktrees.
3	 *
4	 * Responsibilities (plan-draft3 §Worktree Management, D40):
5	 *   - Create a git branch + worktree under <baseDir>/<slug>-<shortid>/
6	 *   - Run bootstrap.commands as a state-machine phase, raising
7	 *     bootstrap_ok / bootstrap_fail events (consumed by Pipeline Engine).
8	 *   - Invoke .yoke/teardown.sh (if present) before git worktree remove.
9	 *   - Ordered cleanup: kill tracked pids → teardown → git worktree remove
10	 *     --force → branch retention decision.
11	 *   - Refuse auto-cleanup if branch has unpushed commits without a PR.
12	 *
13	 * Non-responsibilities:
14	 *   - Does NOT apply state-machine transitions (Pipeline Engine's job).
15	 *   - Does NOT parse NDJSON (StreamJsonParser's job).
16	 *   - Does NOT manage long-running agent sessions (ProcessManager's job).
17	 *
18	 * Review criteria compliance:
19	 *   RC-1  runBootstrap() returns a BootstrapEvent for the Pipeline Engine
20	 *         to apply via transition(); this module never calls transition().
21	 *   RC-2  Branch retention decision uses 'git log --not --remotes',
22	 *         reading the git remote state — not just local refs.
23	 *   RC-3  'git worktree remove --force' is called only after runTeardown().
24	 *   RC-4  Worktree path validated: must be absolute and strictly under baseDir.
25	 */
26	
27	import { execFile } from 'node:child_process';
28	import { promisify } from 'node:util';
29	import fs from 'node:fs';
30	import path from 'node:path';
31	import { makeBranchName, makeWorktreeDirName } from './branch.js';
32	
33	const execFileAsync = promisify(execFile);
34	
35	// ---------------------------------------------------------------------------
36	// Error type
37	// ---------------------------------------------------------------------------
38	
39	export type WorktreeErrorKind =
40	  | 'invalid_path'    // computed path is not absolute
41	  | 'path_traversal'  // computed path escapes the configured baseDir
42	  | 'git_error'       // git command exited non-zero
43	  | 'spawn_failed';   // spawn itself failed (ENOENT, EACCES)
44	
45	export class WorktreeError extends Error {
46	  constructor(
47	    public readonly kind: WorktreeErrorKind,
48	    message: string,
49	    public readonly cause?: unknown,
50	  ) {
51	    super(message);
52	    this.name = 'WorktreeError';
53	  }
54	}
55	
56	// ---------------------------------------------------------------------------
57	// Public types
58	// ---------------------------------------------------------------------------
59	
60	export interface WorktreeInfo {
61	  /** Full git branch name, e.g. 'yoke/add-auth-abc12345'. */
62	  branchName: string;
63	  /** Absolute path to the worktree directory. */
64	  worktreePath: string;
65	}
66	
67	/**
68	 * Event raised by runBootstrap(); consumed by the Pipeline Engine.
69	 * The Pipeline Engine applies the corresponding transition:
70	 *   bootstrap_ok   → (bootstrapping, bootstrap_ok)   → in_progress
71	 *   bootstrap_fail → (bootstrapping, bootstrap_fail) → bootstrap_failed
72	 */
73	export type BootstrapEvent =
74	  | { type: 'bootstrap_ok' }
75	  | {
76	      type: 'bootstrap_fail';
77	      /** The command string (from ResolvedConfig) that exited non-zero. */
78	      failedCommand: string;
79	      exitCode: number;
80	      stderr: string;
81	    };
82	
83	export interface CreateWorktreeOpts {
84	  workflowId: string;
85	  workflowName: string;
86	  /** Absolute path to the base directory for worktrees (e.g. /repo/.worktrees). */
87	  baseDir: string;
88	  /** Git branch prefix. Defaults to 'yoke/'. */
89	  branchPrefix?: string;
90	}
91	
92	export interface RunBootstrapOpts {
93	  worktreePath: string;
94	  /** Shell command strings from ResolvedConfig.worktrees.bootstrap.commands. */
95	  commands: string[];
96	}
97	
98	export interface CleanupOpts {
99	  workflowId: string;
100	  worktreePath: string;
101	  branchName: string;
102	  /** OS PIDs of child processes to kill before teardown. */
103	  trackedPids: number[];
104	  /**
105	   * Milliseconds to wait after SIGTERM before escalating to SIGKILL.
106	   * Defaults to 10 000 ms.
107	   */
108	  gracePeriodMs?: number;
109	}
110	
111	export interface CleanupResult {
112	  worktreeRemoved: boolean;
113	  /**
114	   * True when the worktree was NOT removed because the branch has unpushed
115	   * commits and no corresponding PR was found (AC-5).
116	   */
117	  branchRetained: boolean;
118	  refusedReason?: 'unpushed_commits_no_pr';
119	}
120	
121	/**
122	 * Testability seam for the GitHub PR existence check.
123	 * Production code uses the default implementation that runs 'gh pr list'.
124	 */
125	export type CheckPrFn = (branchName: string, repoRoot: string) => Promise<boolean>;
126	
127	// ---------------------------------------------------------------------------
128	// WorktreeManager
129	// ---------------------------------------------------------------------------
130	
131	export interface WorktreeManagerOpts {
132	  /** Absolute path to the git repository root. */
133	  repoRoot: string;
134	  /**
135	   * Optional override for the PR existence check.
136	   * Defaults to running 'gh pr list --head <branch> --json number'.
137	   * Pass a stub in tests to avoid requiring the gh CLI.
138	   */
139	  checkPr?: CheckPrFn;
140	}
141	
142	export class WorktreeManager {
143	  private readonly repoRoot: string;
144	  private readonly checkPrFn: CheckPrFn;
145	
146	  constructor(opts: WorktreeManagerOpts) {
147	    this.repoRoot = opts.repoRoot;
148	    this.checkPrFn = opts.checkPr ?? defaultCheckPr;
149	  }
150	
151	  // -------------------------------------------------------------------------
152	  // createWorktree — AC-1, RC-4
153	  // -------------------------------------------------------------------------
154	
155	  /**
156	   * Creates a git branch + worktree under baseDir.
157	   *
158	   * Branch name:    yoke/<slug>-<shortid>
159	   * Worktree path:  <baseDir>/<slug>-<shortid>  (absolute, validated)
160	   *
161	   * Returns { branchName, worktreePath } for the caller (Pipeline Engine) to
162	   * persist via applyWorktreeCreated().  This method does NOT write to SQLite —
163	   * the Pipeline Engine is the sole SQLite mutator (AC-5).
164	   *
165	   * @throws {WorktreeError} kind='path_traversal' if computed path escapes baseDir.
166	   * @throws {WorktreeError} kind='git_error' if git worktree add fails.
167	   */
168	  async createWorktree(opts: CreateWorktreeOpts): Promise<WorktreeInfo> {
169	    const { workflowId, workflowName, baseDir, branchPrefix = 'yoke/' } = opts;
170	
171	    const branchName = makeBranchName(workflowName, workflowId, branchPrefix);
172	    const dirName = makeWorktreeDirName(workflowName, workflowId);
173	    // path.resolve ensures the result is absolute even if baseDir is relative.
174	    const worktreePath = path.resolve(baseDir, dirName);
175	
176	    // RC-4: validate path is absolute and strictly under baseDir.
177	    this._validateWorktreePath(worktreePath, baseDir);
178	
179	    // Ensure the base directory exists before git worktree add creates the subdir.
180	    fs.mkdirSync(path.resolve(baseDir), { recursive: true });
181	
182	    // 'git worktree add -b <branch> <path>' creates the branch at HEAD and
183	    // checks it out in the new worktree directory in one atomic git operation.
184	    try {
185	      await execFileAsync('git', [
186	        '-C', this.repoRoot,
187	        'worktree', 'add',
188	        '-b', branchName,
189	        worktreePath,
190	      ]);
191	    } catch (err) {
192	      throw new WorktreeError(
193	        'git_error',
194	        `Failed to create worktree '${worktreePath}' on branch '${branchName}': ${(err as Error).message}`,
195	        err,
196	      );
197	    }
198	
199	    return { branchName, worktreePath };
200	  }

1	/**
2	 * Pre/Post Command Runner — executes pre/post command arrays for a phase.
3	 *
4	 * Responsibilities:
5	 *   - Spawn each PrePostCommand in declared order with shell:false.
6	 *   - Enforce per-command wall-clock timeout (default DEFAULT_TIMEOUT_S = 15 min).
7	 *   - Stream stdout/stderr to the session log as prepost.command.* frames (AC-2).
8	 *   - Resolve exit code → action via action-grammar.ts.
9	 *   - Stop on the first non-continue action and return it to the caller.
10	 *   - Return { kind: 'complete' } when all commands complete with "continue".
11	 *
12	 * Non-responsibilities:
13	 *   - Action execution (goto, retry, stop, fail) — done by the Pipeline Engine.
14	 *   - Any SQLite write — Pipeline Engine is the sole SQLite mutator.
15	 *   - Spawning the agent session command — that is ProcessManager's job.
16	 *
17	 * Frame format written to the session log (JSONL):
18	 *   {"type":"prepost.command.start","name":"<n>","when":"pre|post","cmd":[...],"ts":"<iso>"}
19	 *   {"type":"prepost.command.stdout","name":"<n>","when":"pre|post","text":"<line>"}
20	 *   {"type":"prepost.command.stderr","name":"<n>","when":"pre|post","text":"<chunk>"}
21	 *   {"type":"prepost.command.exit","name":"<n>","when":"pre|post","exit_code":<n>,"elapsed_ms":<n>}
22	 *   {"type":"prepost.command.exit","name":"<n>","when":"pre|post","exit_code":null,"elapsed_ms":<n>,"timed_out":true}
23	 *
24	 * Log writes are serialised via a promise chain (_writeQueue) so frames arrive
25	 * in emission order even though writeLine() is async. The chain is always
26	 * drained before the function returns, so callers see a fully-flushed log.
27	 */
28	
29	import { spawn as nodeSpawn } from 'node:child_process';
30	import { createInterface as createReadline } from 'node:readline';
31	import type { ActionValue, PrePostCommand } from '../../shared/types/config.js';
32	import type { SessionLogWriter } from '../session-log/writer.js';
33	import { isContinue, resolveAction } from './action-grammar.js';
34	
35	// ---------------------------------------------------------------------------
36	// Constants
37	// ---------------------------------------------------------------------------
38	
39	/** Default per-command wall-clock timeout (plan-draft3 §Phase Pre/Post Commands). */
40	export const DEFAULT_TIMEOUT_S = 15 * 60;
41	
42	/**
43	 * Grace period between SIGTERM and SIGKILL when the timeout fires.
44	 * Kept short (5 s) because pre/post commands must not stall the pipeline.
45	 */
46	const SIGKILL_GRACE_MS = 5_000;
47	
48	// ---------------------------------------------------------------------------
49	// Public result type
50	// ---------------------------------------------------------------------------
51	
52	export type RunCommandsResult =
53	  /** All commands completed with the "continue" action. */
54	  | { kind: 'complete' }
55	  /** A command produced a non-continue action. Pipeline Engine must execute it. */
56	  | { kind: 'action'; command: string; action: ActionValue }
57	  /** A command exceeded its wall-clock timeout. */
58	  | { kind: 'timeout'; command: string }
59	  /** A command could not be spawned (ENOENT, bad run array, etc.). */
60	  | { kind: 'spawn_failed'; command: string; error: Error }
61	  /** A command exited with a code not declared in its actions map. */
62	  | { kind: 'unhandled_exit'; command: string; exitCode: number };
63	
64	// ---------------------------------------------------------------------------
65	// Options
66	// ---------------------------------------------------------------------------
67	
68	export interface RunCommandsOpts {
69	  /** Array of pre: or post: commands from the phase config. */
70	  commands: PrePostCommand[];
71	  /** Absolute path to the worktree directory (CWD for each command). */
72	  worktreePath: string;
73	  /**
74	   * Open session log writer. The runner appends prepost.command.* frames to it.
75	   * Caller must have already called writer.open() before passing it here.
76	   * The runner does NOT close the writer — the same writer is shared with the
77	   * Process Manager for the agent session.
78	   */
79	  logWriter: SessionLogWriter;
80	  /** Whether these are pre- or post-commands (recorded in frame metadata). */
81	  when: 'pre' | 'post';
82	  /**
83	   * Additional environment variables merged over process.env (then over cmd.env).
84	   * Mirrors the env injection contract of JigProcessManager.
85	   */
86	  env?: Record<string, string>;
87	}
88	
89	// ---------------------------------------------------------------------------
90	// Public entry point
91	// ---------------------------------------------------------------------------
92	
93	/**
94	 * Runs an array of pre/post commands sequentially.
95	 *
96	 * Stops after the first non-continue action (or error) and returns the result.
97	 * All log frames are flushed before returning.
98	 *
99	 * @param opts  Runner options — see RunCommandsOpts.
100	 * @returns     RunCommandsResult indicating how the command array concluded.
101	 */
102	export async function runCommands(opts: RunCommandsOpts): Promise<RunCommandsResult> {
103	  for (const cmd of opts.commands) {
104	    const result = await _runOneCommand(cmd, opts);
105	    if (result.kind !== 'continue_next') {
106	      return result;
107	    }
108	  }
109	  return { kind: 'complete' };
110	}
111	
112	// ---------------------------------------------------------------------------
113	// Internal single-command runner
114	// ---------------------------------------------------------------------------
115	
116	/** Internal result — adds 'continue_next' sentinel for the loop. */
117	type OneCommandResult =
118	  | { kind: 'continue_next' }
119	  | RunCommandsResult;
120	
121	async function _runOneCommand(
122	  cmd: PrePostCommand,
123	  opts: RunCommandsOpts,
124	): Promise<OneCommandResult> {
125	  const { worktreePath, logWriter, when, env: callerEnv } = opts;
126	  const timeoutMs = (cmd.timeout_s ?? DEFAULT_TIMEOUT_S) * 1_000;
127	  const startTs = Date.now();
128	
129	  // Serialised write queue — ensures frames arrive in emission order.
130	  let _writeQueue: Promise<void> = Promise.resolve();
131	  const writeFrame = (frame: Record<string, unknown>): void => {
132	    _writeQueue = _writeQueue.then(() => logWriter.writeLine(JSON.stringify(frame))).catch(() => {});
133	  };
134	
135	  // Merge environment: process.env < caller extras < command-specific env.
136	  const mergedEnv: NodeJS.ProcessEnv = {
137	    ...process.env,
138	    ...(callerEnv ?? {}),
139	    ...(cmd.env ?? {}),
140	  };
141	
142	  // Guard: a pre/post command must have at least one element in its run array.
143	  const [command, ...args] = cmd.run;
144	  if (!command) {
145	    return {
146	      kind: 'spawn_failed',
147	      command: cmd.name,
148	      error: new Error(`prepost command '${cmd.name}': run array is empty`),
149	    };
150	  }
151	
152	  // Pre-spawn frame.
153	  writeFrame({
154	    type: 'prepost.command.start',
155	    name: cmd.name,
156	    when,
157	    cmd: cmd.run,
158	    ts: new Date().toISOString(),
159	  });
160	
161	  // Spawn.
162	  let child: ReturnType<typeof nodeSpawn>;
163	  try {
164	    child = nodeSpawn(command, args, {
165	      cwd: worktreePath,
166	      stdio: ['ignore', 'pipe', 'pipe'],
167	      env: mergedEnv,
168	      detached: true,
169	    });
170	  } catch (err) {
171	    // Synchronous spawn failure — only happens if command is not a string, etc.
172	    return {
173	      kind: 'spawn_failed',
174	      command: cmd.name,
175	      error: err instanceof Error ? err : new Error(String(err)),
176	    };
177	  }
178	
179	  // Allow Node.js to exit without waiting for the child.
180	  child.unref();
181	
182	  // Outcome promise — resolves once the child closes (all I/O drained).
183	  type Outcome =
184	    | { type: 'close'; code: number | null }
185	    | { type: 'spawn_error'; err: Error }
186	    | { type: 'timeout' };
187	
188	  const outcome = await new Promise<Outcome>((resolve) => {
189	    let resolved = false;
190	    const settle = (o: Outcome): void => {
191	      if (!resolved) {
192	        resolved = true;
193	        resolve(o);
194	      }
195	    };
196	
197	    // Wall-clock timeout.
198	    const pgid = child.pid;
199	    const timeoutId = setTimeout(() => {
200	      // SIGTERM first; SIGKILL after grace period if still alive.
201	      if (pgid !== undefined) {
202	        try {
203	          process.kill(-pgid, 'SIGTERM');
204	        } catch {
205	          // Process already gone between spawn and timeout — acceptable.
206	        }
207	        setTimeout(() => {
208	          try {
209	            process.kill(-pgid, 'SIGKILL');
210	          } catch {
211	            // Process already gone — acceptable.
212	          }
213	        }, SIGKILL_GRACE_MS);
214	      }
215	      settle({ type: 'timeout' });
216	    }, timeoutMs);
217	
218	    // stdout: line-buffered, one frame per line.
219	    const rl = createReadline({ input: child.stdout!, crlfDelay: Infinity });
220	    rl.on('line', (line) => {
221	      writeFrame({ type: 'prepost.command.stdout', name: cmd.name, when, text: line });
222	    });
223	
224	    // stderr: buffered by line for cleaner frames; remainder flushed on close.
225	    let stderrBuf = '';
226	    child.stderr!.on('data', (chunk: Buffer) => {
227	      stderrBuf += chunk.toString('utf8');
228	      const lines = stderrBuf.split('\n');
229	      stderrBuf = lines.pop() ?? '';
230	      for (const line of lines) {
231	        writeFrame({ type: 'prepost.command.stderr', name: cmd.name, when, text: line });
232	      }
233	    });
234	    child.stderr!.on('close', () => {
235	      if (stderrBuf) {
236	        writeFrame({ type: 'prepost.command.stderr', name: cmd.name, when, text: stderrBuf });
237	        stderrBuf = '';
238	      }
239	    });
240	
241	    // Async spawn error (ENOENT, EACCES, etc.) — fires instead of / before 'close'.
242	    child.on('error', (err: Error) => {
243	      clearTimeout(timeoutId);
244	      settle({ type: 'spawn_error', err });
245	    });
246	
247	    // 'close' fires after the child process exits AND all stdio streams are
248	    // drained — guarantees all stdout/stderr events have already fired.
249	    child.on('close', (code) => {
250	      clearTimeout(timeoutId);
251	      settle({ type: 'close', code });
252	    });
253	  });
254	
255	  // Drain all pending log writes before writing the exit frame.
256	  await _writeQueue;
257	
258	  if (outcome.type === 'spawn_error') {
259	    return { kind: 'spawn_failed', command: cmd.name, error: outcome.err };
260	  }
261	
262	  const elapsedMs = Date.now() - startTs;
263	
264	  if (outcome.type === 'timeout') {
265	    writeFrame({
266	      type: 'prepost.command.exit',
267	      name: cmd.name,
268	      when,
269	      exit_code: null,
270	      elapsed_ms: elapsedMs,
271	      timed_out: true,
272	    });
273	    await _writeQueue;
274	    return { kind: 'timeout', command: cmd.name };
275	  }
276	
277	  // Normal exit.
278	  const exitCode = outcome.code ?? -1;
279	  writeFrame({
280	    type: 'prepost.command.exit',
281	    name: cmd.name,
282	    when,
283	    exit_code: exitCode,
284	    elapsed_ms: elapsedMs,
285	  });
286	  await _writeQueue;
287	
288	  const action = resolveAction(cmd.actions, exitCode);
289	  if (action === null) {
290	    return { kind: 'unhandled_exit', command: cmd.name, exitCode };
291	  }
292	
293	  if (isContinue(action)) {
294	    return { kind: 'continue_next' };
295	  }
296	
297	  return { kind: 'action', command: cmd.name, action };
298	}
299

1	/**
2	 * Yoke Fastify HTTP + WebSocket server.
3	 *
4	 * This module replaces the interim Node.js http.Server in http.ts.  It
5	 * implements:
6	 *   - All HTTP companion endpoints from protocol-websocket.md §7.
7	 *   - WebSocket route at /stream (protocol per ws.ts).
8	 *   - Exclusive 127.0.0.1 binding (D57, RC: no 0.0.0.0 code path).
9	 *
10	 * Design invariants:
11	 *   - All reads use db.reader() (read-only connection).
12	 *   - No SQLite writes in this module (RC-3). The attention ack endpoint
13	 *     delegates the write to an injected AckAttentionFn callback so the API
14	 *     layer itself has no write path.
15	 *   - No authentication middleware (D57).
16	 *   - No 0.0.0.0 bind path exists anywhere in this file.
17	 */
18	
19	import Fastify, { type FastifyInstance, type FastifyRequest, type FastifyReply } from 'fastify';
20	import fastifyWebsocket, { type SocketStream } from '@fastify/websocket';
21	import type { DbPool } from '../storage/db.js';
22	import { readLogPage } from '../session-log/reader.js';
23	import {
24	  SessionSeqStore,
25	  BackfillBuffer,
26	  createWsHandler,
27	} from './ws.js';
28	import { IdempotencyStore } from './idempotency.js';
29	
30	// ---------------------------------------------------------------------------
31	// Internal helpers
32	// ---------------------------------------------------------------------------
33	
34	function badRequest(reply: FastifyReply, message: string): FastifyReply {
35	  return reply.status(400).send({ error: message });
36	}
37	
38	function notFound(reply: FastifyReply, message = 'not found'): FastifyReply {
39	  return reply.status(404).send({ error: message });
40	}
41	
42	// ---------------------------------------------------------------------------
43	// Snapshot helpers
44	// ---------------------------------------------------------------------------
45	
46	interface WorkflowRow {
47	  id: string;
48	  name: string;
49	  status: string;
50	  current_stage: string | null;
51	  created_at: string;
52	  updated_at: string;
53	  active_sessions: number;
54	}
55	
56	// ---------------------------------------------------------------------------
57	// Server factory
58	// ---------------------------------------------------------------------------
59	
60	export interface ServerOptions {
61	  /**
62	   * Bind host — MUST be '127.0.0.1'. Passing any other value throws at
63	   * listen time. Default: '127.0.0.1'.
64	   */
65	  host?: '127.0.0.1';
66	  /** Server port. 0 = OS-assigned (default for tests). */
67	  port?: number;
68	}
69	
70	/** Shared in-memory state for the WS layer — exposed so tests and the pipeline engine integration can push frames. */
71	export interface ServerState {
72	  seqStore: SessionSeqStore;
73	  backfillBuffer: BackfillBuffer;
74	  idempotency: IdempotencyStore;
75	}
76	
77	export interface ServerHandle {
78	  fastify: FastifyInstance;
79	  state: ServerState;
80	}
81	
82	/**
83	 * Result returned by AckAttentionFn to the API layer.
84	 * The callback owns both the read and the write for the ack operation so that
85	 * the API layer has no SQLite write path (RC-3).
86	 */
87	export type AckAttentionResult =
88	  | { status: 'acknowledged'; id: number }
89	  | { status: 'already_acknowledged'; id: number }
90	  | { status: 'not_found' };
91	
92	/**
93	 * Callback that handles POST /api/workflows/:id/attention/:attentionId/ack.
94	 * Implementations must: verify the attention item exists and belongs to
95	 * workflowId, check acknowledged_at, write acknowledged_at = datetime('now')
96	 * if not already set, and return the appropriate result.
97	 *
98	 * The write MUST NOT happen inside the API layer (RC-3). Callers inject this
99	 * callback so the actual SQLite write lives in the pipeline engine layer.
100	 */
101	export type AckAttentionFn = (workflowId: string, attentionId: number) => AckAttentionResult;
102	
103	/**
104	 * Optional callbacks injected into the server at creation time.
105	 * These allow the API layer to delegate writes to the pipeline engine layer
106	 * without the API module having any SQLite write path (RC-3).
107	 */
108	export interface ServerCallbacks {
109	  /**
110	   * Called when a client POSTs to
111	   * /api/workflows/:id/attention/:attentionId/ack.
112	   * If omitted, the endpoint returns 501 Not Implemented.
113	   */
114	  ackAttention?: AckAttentionFn;
115	}
116	
117	/**
118	 * Creates and configures the Fastify server.
119	 *
120	 * Callers must await fastify.listen(...) to start accepting connections.
121	 * The returned instance's .server.address() gives the bound port.
122	 *
123	 * @param db         DbPool opened by the caller.
124	 * @param callbacks  Optional injected handlers for write operations (RC-3).
125	 */
126	export async function createServer(db: DbPool, callbacks: ServerCallbacks = {}): Promise<ServerHandle> {
127	  const fastify = Fastify({ logger: false });
128	
129	  // Shared state for the WS layer.
130	  const seqStore = new SessionSeqStore();
131	  const backfillBuffer = new BackfillBuffer();
132	  const idempotency = new IdempotencyStore();
133	
134	  // Register WebSocket plugin.
135	  await fastify.register(fastifyWebsocket);
136	
137	  // WebSocket route at /stream (§4 Lifecycle).
138	  // Registered directly on the root fastify instance so it inherits the
139	  // @fastify/websocket plugin decoration without sub-plugin scoping issues.
140	  const wsHandler = createWsHandler({ db, idempotency, seqStore, backfillBuffer });
141	  fastify.get('/stream', { websocket: true }, (connection: SocketStream) => {
142	    wsHandler(connection.socket);
143	  });
144	
145	  // -------------------------------------------------------------------------
146	  // §7 HTTP companion endpoints
147	  // All read from db.reader() — no workflow/item state writes.
148	  // -------------------------------------------------------------------------
149	
150	  // GET /api/workflows?status=&q=&before=&limit=
151	  // Keyset pagination (D47). Ordered by created_at DESC.
152	  fastify.get(
153	    '/api/workflows',
154	    async (req: FastifyRequest, reply: FastifyReply) => {
155	      const qs = req.query as Record<string, string | undefined>;
156	      const limitRaw = parseInt(qs.limit ?? '20', 10);
157	      if (!isFinite(limitRaw) || limitRaw < 1) return badRequest(reply, 'limit must be a positive integer');
158	      const limit = Math.min(limitRaw, 100);
159	
160	      let sql =
161	        'SELECT w.id, w.name, w.status, w.current_stage, w.created_at, w.updated_at,' +
162	        ' (SELECT COUNT(*) FROM sessions s WHERE s.workflow_id = w.id AND s.ended_at IS NULL) AS active_sessions' +
163	        ' FROM workflows w WHERE 1=1';
164	      const params: unknown[] = [];
165	
166	      if (qs.status) {
167	        sql += ' AND w.status = ?';
168	        params.push(qs.status);
169	      }
170	      if (qs.q) {
171	        sql += ' AND w.name LIKE ?';
172	        params.push(`%${qs.q}%`);
173	      }
174	      if (qs.before) {
175	        sql += ' AND w.created_at < ?';
176	        params.push(qs.before);
177	      }
178	      sql += ` ORDER BY w.created_at DESC LIMIT ${limit + 1}`;
179	
180	      const rows = db.reader().prepare(sql).all(...params) as WorkflowRow[];
181	      const hasMore = rows.length > limit;
182	      const workflows = hasMore ? rows.slice(0, limit) : rows;
183	
184	      return reply.send({
185	        workflows,
186	        hasMore,
187	        nextBefore: hasMore ? workflows[workflows.length - 1].created_at : null,
188	      });
189	    },
190	  );
191	
192	  // GET /api/workflows/:id/timeline
193	  // Merged SQLite events + JSONL (§Obs, D34).
194	  fastify.get(
195	    '/api/workflows/:id/timeline',
196	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
197	      const { id } = req.params;
198	      const reader = db.reader();
199	
200	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
201	      if (!wf) return notFound(reply, 'workflow not found');
202	
203	      const events = reader
204	        .prepare(
205	          'SELECT id, ts, workflow_id, item_id, session_id, stage, phase, attempt, event_type, level, message, extra FROM events WHERE workflow_id = ? ORDER BY ts, id',
206	        )
207	        .all(id) as Array<{
208	          id: number;
209	          ts: string;
210	          workflow_id: string;
211	          item_id: string | null;
212	          session_id: string | null;
213	          stage: string | null;
214	          phase: string | null;
215	          attempt: number | null;
216	          event_type: string;
217	          level: string;
218	          message: string;
219	          extra: string | null;
220	        }>;
221	
222	      return reply.send({
223	        workflowId: id,
224	        events: events.map((e) => ({
225	          ...e,
226	          extra: e.extra ? (() => { try { return JSON.parse(e.extra!); } catch { return e.extra; } })() : null,
227	        })),
228	      });
229	    },
230	  );
231	
232	  // GET /api/sessions/:id/log?sinceSeq=&limit=
233	  // Paged stream-json fetch (D48a). Reads from JSONL file via readLogPage.
234	  fastify.get(
235	    '/api/sessions/:id/log',
236	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
237	      const { id } = req.params;
238	      const qs = req.query as Record<string, string | undefined>;
239	
240	      const sinceSeqRaw = qs.sinceSeq !== undefined ? parseInt(qs.sinceSeq, 10) : 0;
241	      const limitRaw = qs.limit !== undefined ? parseInt(qs.limit, 10) : 100;
242	
243	      if (!isFinite(sinceSeqRaw) || sinceSeqRaw < 0) return badRequest(reply, 'sinceSeq must be a non-negative integer');
244	      if (!isFinite(limitRaw) || limitRaw < 1) return badRequest(reply, 'limit must be a positive integer');
245	
246	      const sinceSeq = Math.max(0, sinceSeqRaw);
247	      const limit = Math.max(1, limitRaw);
248	
249	      const reader = db.reader();
250	      const row = reader
251	        .prepare('SELECT session_log_path FROM sessions WHERE id = ?')
252	        .get(id) as { session_log_path: string | null } | undefined;
253	
254	      if (!row) return notFound(reply, 'session not found');
255	
256	      if (!row.session_log_path) {
257	        return reply.send({ entries: [], nextSeq: sinceSeq, hasMore: false });
258	      }
259	
260	      const page = await readLogPage(row.session_log_path, sinceSeq, limit);
261	      if (!page) {
262	        return reply.send({ entries: [], nextSeq: sinceSeq, hasMore: false });
263	      }
264	
265	      return reply.send(page);
266	    },
267	  );
268	
269	  // GET /api/workflows/:id/usage?groupBy=feature|phase|profile|session
270	  // Token aggregates per groupBy dimension.
271	  fastify.get(
272	    '/api/workflows/:id/usage',
273	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
274	      const { id } = req.params;
275	      const qs = req.query as Record<string, string | undefined>;
276	      const groupBy = qs.groupBy ?? 'session';
277	
278	      const validGroupBy = ['feature', 'phase', 'profile', 'session'];
279	      if (!validGroupBy.includes(groupBy)) {
280	        return badRequest(reply, `groupBy must be one of: ${validGroupBy.join(', ')}`);
281	      }
282	
283	      const reader = db.reader();
284	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
285	      if (!wf) return notFound(reply, 'workflow not found');
286	
287	      // Map groupBy dimension to SQLite column.
288	      const groupCol: Record<string, string> = {
289	        feature: 'item_id',
290	        phase: 'phase',
291	        profile: 'agent_profile',
292	        session: 'id',
293	      };
294	      const col = groupCol[groupBy];
295	
296	      const rows = reader
297	        .prepare(
298	          `SELECT ${col} AS dimension,
299	                  SUM(input_tokens) AS input_tokens,
300	                  SUM(output_tokens) AS output_tokens,
301	                  SUM(cache_creation_input_tokens) AS cache_creation_input_tokens,
302	                  SUM(cache_read_input_tokens) AS cache_read_input_tokens,
303	                  COUNT(*) AS session_count
304	           FROM sessions
305	           WHERE workflow_id = ?
306	           GROUP BY ${col}
307	           ORDER BY input_tokens DESC`,
308	        )
309	        .all(id);
310	
311	      return reply.send({ workflowId: id, groupBy, rows });
312	    },
313	  );
314	
315	  // GET /api/workflows/:id/usage/timeseries?bucket=hour|day
316	  // Usage timeseries bucketed by hour or day.
317	  fastify.get(
318	    '/api/workflows/:id/usage/timeseries',
319	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
320	      const { id } = req.params;
321	      const qs = req.query as Record<string, string | undefined>;
322	      const bucket = qs.bucket ?? 'hour';
323	
324	      if (bucket !== 'hour' && bucket !== 'day') {
325	        return badRequest(reply, 'bucket must be hour or day');
326	      }
327	
328	      const reader = db.reader();
329	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
330	      if (!wf) return notFound(reply, 'workflow not found');
331	
332	      // SQLite strftime format for the requested bucket.
333	      const fmt = bucket === 'hour' ? '%Y-%m-%dT%H:00:00Z' : '%Y-%m-%dT00:00:00Z';
334	
335	      const rows = reader
336	        .prepare(
337	          `SELECT strftime('${fmt}', started_at) AS bucket,
338	                  SUM(input_tokens) AS input_tokens,
339	                  SUM(output_tokens) AS output_tokens,
340	                  SUM(cache_creation_input_tokens) AS cache_creation_input_tokens,
341	                  SUM(cache_read_input_tokens) AS cache_read_input_tokens,
342	                  COUNT(*) AS session_count
343	           FROM sessions
344	           WHERE workflow_id = ?
345	           GROUP BY bucket
346	           ORDER BY bucket ASC`,
347	        )
348	        .all(id);
349	
350	      return reply.send({ workflowId: id, bucket, rows });
351	    },
352	  );
353	
354	  // POST /api/workflows/:id/control
355	  // Idempotent manual control (mirrors WS control frame).
356	  fastify.post(
357	    '/api/workflows/:id/control',
358	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
359	      const { id } = req.params;
360	      const body = req.body as {
361	        commandId?: string;
362	        action?: string;
363	        itemId?: string;
364	        stageId?: string;
365	        extra?: unknown;
366	      } | null;
367	
368	      if (!body?.commandId) return badRequest(reply, 'commandId is required');
369	      if (!body.action) return badRequest(reply, 'action is required');
370	
371	      const reader = db.reader();
372	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
373	      if (!wf) return notFound(reply, 'workflow not found');
374	
375	      // Idempotency check (AC-4, RC: not by re-executing).
376	      const cached = idempotency.get(body.commandId);
377	      if (cached !== undefined) {
378	        return reply.status(200).send(cached);
379	      }
380	
381	      // Cache and return accepted response. Actual execution deferred to pipeline engine.
382	      const response = {
383	        status: 'accepted',
384	        commandId: body.commandId,
385	        workflowId: id,
386	        action: body.action,
387	      };
388	      idempotency.set(body.commandId, response);
389	
390	      return reply.status(202).send(response);
391	    },
392	  );
393	
394	  // POST /api/workflows/:id/attention/:attentionId/ack
395	  // Clear a pending attention item.
396	  // The write is delegated to callbacks.ackAttention (RC-3 — no writes in API layer).
397	  fastify.post(
398	    '/api/workflows/:id/attention/:attentionId/ack',
399	    async (
400	      req: FastifyRequest<{ Params: { id: string; attentionId: string } }>,
401	      reply: FastifyReply,
402	    ) => {
403	      const { id, attentionId } = req.params;
404	      const attId = parseInt(attentionId, 10);
405	      if (!isFinite(attId)) return badRequest(reply, 'attentionId must be an integer');
406	
407	      if (!callbacks.ackAttention) {
408	        return reply.status(501).send({ error: 'attention ack not configured' });
409	      }
410	
411	      // Verify the workflow exists using the read-only connection.
412	      const wf = db.reader().prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
413	      if (!wf) return notFound(reply, 'workflow not found');
414	
415	      // Delegate the pending_attention read + write to the injected callback
416	      // so that no SQLite write occurs inside the API layer (RC-3).
417	      const result = callbacks.ackAttention(id, attId);
418	      if (result.status === 'not_found') return notFound(reply, 'attention item not found');
419	      return reply.send(result);
420	    },
421	  );
422	
423	  return { fastify, state: { seqStore, backfillBuffer, idempotency } };
424	}
