426	// ---------------------------------------------------------------------------
427	// Convenience: listen with enforced 127.0.0.1 binding (AC-6, RC)
428	// ---------------------------------------------------------------------------
429	
430	/**
431	 * Creates the server and starts listening on 127.0.0.1. Throws if host is
432	 * anything other than '127.0.0.1' — no 0.0.0.0 bind path exists (D57).
433	 *
434	 * @returns The listening Fastify instance.
435	 */
436	export async function listenServer(
437	  db: DbPool,
438	  opts: ServerOptions = {},
439	  callbacks: ServerCallbacks = {},
440	): Promise<FastifyInstance> {
441	  const host = opts.host ?? '127.0.0.1';
442	  if (host !== '127.0.0.1') {
443	    throw new Error(`Server must bind to 127.0.0.1, not ${host} (D57)`);
444	  }
445	  const port = opts.port ?? 0;
446	
447	  const { fastify } = await createServer(db, callbacks);
448	  await fastify.listen({ host, port });
449	  return fastify;
450	}
