0	/**
1	 * Pipeline Engine — core atomic state-machine operations over SQLite.
2	 *
3	 * Source: plan-draft3.md §State Machine, §Retry, §Crash Recovery;
4	 * docs/design/state-machine-transitions.md; feat-pipeline-engine spec.
5	 *
6	 * ## Guarantees
7	 *
8	 *   AC-5  Pipeline Engine is the ONLY component that mutates SQLite
9	 *         workflow/item/session state.  No other module calls db.writer
10	 *         directly.
11	 *   AC-6  Every transition is committed inside db.transaction() before any
12	 *         observable external side effect (process spawn, WS frame emission).
13	 *   RC-1  No long-lived in-memory workflow state.  Every public function
14	 *         re-reads SQLite at the start of each call; none caches item/
15	 *         workflow rows between calls.
16	 *
17	 * ## Exported functions
18	 *
19	 *   applyItemTransition   — atomically apply a state-machine event to an item
20	 *   checkStageComplete    — probe whether all items in a stage are terminal
21	 *   buildCrashRecovery    — rebuild projection from SQLite on startup
22	 *
23	 * ## Non-responsibilities
24	 *
25	 *   - Does NOT spawn processes (ProcessManager's job).
26	 *   - Does NOT create worktrees (WorktreeManager's job).
27	 *   - Does NOT assemble prompts (Prompt Assembler's job).
28	 *   - Does NOT parse NDJSON (StreamJsonParser's job).
29	 *   - Does NOT run the scheduling event loop (higher-level concern).
30	 */
31	
32	import type { DbPool } from '../storage/db.js';
33	import type { State, Event } from '../state-machine/states.js';
34	import { transition } from '../state-machine/transitions.js';
35	import type { TransitionResult } from '../state-machine/transitions.js';
36	import type { FailureClass } from '../state-machine/classifier.js';
37	import {
38	  computeRetryDecision,
39	  DEFAULT_RETRY_LADDER,
