44	// ---------------------------------------------------------------------------
45	// Public types — action grammar (subset consumed by the engine)
46	// ---------------------------------------------------------------------------
47	
48	/** Resolved action from a pre/post command's exit-code map. */
49	export interface ResolvedAction {
50	  kind: 'continue' | 'goto' | 'retry' | 'stop-and-ask' | 'stop' | 'fail';
51	  /** Target phase name for 'goto' actions. */
52	  goto?: string;
53	  /** Max goto loops to this destination (default 3). */
54	  maxRevisits?: number;
55	  /** Retry configuration for 'retry' actions (not used by outer ladder). */
56	  retry?: { mode: Exclude<RetryMode, 'awaiting_user'>; max: number };
57	  /** Failure reason for 'fail' actions. */
58	  failReason?: string;
59	}
60	
61	// ---------------------------------------------------------------------------
62	// Public types — guard context
63	// ---------------------------------------------------------------------------
64	
65	/**
66	 * Caller-supplied context for guard evaluation.
67	 *
68	 * The engine reads state-dependent guards (retry_count, depends_on,
69	 * worktree_path) directly from SQLite.  Guards that come from external
70	 * events or config are provided here.
71	 */
72	export interface GuardContext {
73	  /** For session_fail: failure classifier result. */
74	  classifierResult?: FailureClass;
75	  /** For session_ok / post_command_action=continue: are there more phases? */
76	  morePhases?: boolean;
77	  /** For session_ok: all post commands resolved to continue. */
78	  allPostCommandsOk?: boolean;
79	  /** For session_ok: artifact validators passed. */
80	  validatorsOk?: boolean;
81	  /** For session_ok: items_from diff check passed. */
82	  diffCheckOk?: boolean;
83	  /** For post_command_action: the resolved action from the post command. */
84	  postCommandAction?: ResolvedAction;
85	  /** For pre_command_failed: which action kind fired. */
86	  preCommandAction?: 'fail' | 'stop-and-ask';
87	  /**
88	   * Per-phase retry configuration.  Defaults to DEFAULT_MAX_OUTER_RETRIES /
89	   * DEFAULT_RETRY_LADDER when not supplied.
90	   */
91	  maxOuterRetries?: number;
92	  retryLadder?: readonly RetryMode[];
93	  /**
94	   * For awaiting_retry → backoff_elapsed: the retry mode chosen when we
95	   * entered awaiting_retry.  The caller must pass this back so the engine
96	   * can return it (used by the orchestration loop to assemble the prompt).
97	   * If absent, the engine derives it from ladder[retry_count - 1].
98	   */
99	  currentRetryMode?: Exclude<RetryMode, 'awaiting_user'>;
100	  /** For phase advance: the name of the next phase in the stage. */
101	  nextPhase?: string;
102	}
