118	  attempt: number;
119	  event: Event;
120	  guardCtx?: GuardContext;
121	  /**
122	   * RC-4: whether the *next* stage (or this stage, for a re-entry gate) has
123	   * `needs_approval: true` in the pipeline config.
124	   *
125	   * When this is true AND `stageComplete` becomes true inside the transaction,
126	   * the engine:
127	   *   1. Inserts `pending_attention{kind='stage_needs_approval'}`.
128	   *   2. Sets `workflows.status = 'pending_stage_approval'`.
129	   *
130	   * The workflow resumes when the orchestration loop receives a
131	   * `stage_approval_granted` event and resets `workflows.status`.
132	   */
133	  needsApproval?: boolean;
