144	   * Retry mode to use for the next session when newState = 'awaiting_retry'.
145	   * Absent for all other newState values.
146	   */
147	  retryMode?: Exclude<RetryMode, 'awaiting_user'>;
148	  /** True if dependents were cascade-blocked within the same transaction. */
149	  cascadeBlocked: boolean;
