205	// eslint-disable-next-line @typescript-eslint/no-explicit-any
206	type SqliteDb = { prepare(sql: string): any };
207	
208	function writeEvent(db: SqliteDb, p: WriteEventParams): void {
209	  db.prepare(`
210	    INSERT INTO events
211	      (ts, workflow_id, item_id, session_id, stage, phase, attempt,
212	       event_type, level, message, extra)
213	    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
214	  `).run(
215	    p.ts,
216	    p.workflowId,
217	    p.itemId,
218	    p.sessionId,
219	    p.stage,
220	    p.phase,
221	    p.attempt,
222	    p.eventType,
223	    p.level,
224	    p.message,
225	    p.extra ?? null,
226	  );
227	}
