229	function writePendingAttention(
230	  db: SqliteDb,
231	  workflowId: string,
232	  kind: string,
233	  payload: Record<string, unknown>,
234	  now: string,
235	): void {
236	  db.prepare(`
237	    INSERT INTO pending_attention (workflow_id, kind, payload, created_at)
238	    VALUES (?, ?, ?, ?)
239	  `).run(workflowId, kind, JSON.stringify(payload), now);
240	}
