242	// ---------------------------------------------------------------------------
243	// Internal: derive pending_attention kind from side-effect labels
244	// ---------------------------------------------------------------------------
245	
246	const PENDING_ATTENTION_LABELS: Record<string, string> = {
247	  'insert pending_attention{kind=bootstrap_failed}': 'bootstrap_failed',
248	  'insert pending_attention': 'awaiting_user_retry',
249	  'insert pending_attention{kind=revisit_limit}': 'revisit_limit',
250	  'insert pending_attention{kind=stage_needs_approval}': 'stage_needs_approval',
251	};
252	
253	function pendingAttentionKindFromEffects(
254	  sideEffects: readonly string[],
255	): string | null {
256	  for (const effect of sideEffects) {
257	    const kind = PENDING_ATTENTION_LABELS[effect];
258	    if (kind) return kind;
259	    // Fuzzy match for labels containing 'pending_attention'
260	    if (effect.includes('pending_attention') && effect.includes('insert')) {
261	      const m = /kind=([^}]+)/.exec(effect);
262	      return m ? m[1] : 'awaiting_user_retry';
263	    }
264	  }
265	  return null;
266	}
