268	// ---------------------------------------------------------------------------
269	// Internal: revisit counter (RC-3: per item_id + destination_phase pair)
270	// ---------------------------------------------------------------------------
271	
272	function countRevisitEvents(
273	  db: SqliteDb,
274	  itemId: string,
275	  destination: string,
276	): number {
277	  const row = db
278	    .prepare(`
279	      SELECT COUNT(*) AS cnt FROM events
280	       WHERE item_id = ?
281	         AND event_type = 'prepost.revisit'
282	         AND json_extract(extra, '$.destination') = ?
283	    `)
284	    .get(itemId, destination) as { cnt: number };
285	  return row.cnt;
286	}
