288	function insertRevisitEvent(
289	  db: SqliteDb,
290	  p: { workflowId: string; itemId: string; sessionId: string | null; stage: string; phase: string; attempt: number },
291	  destination: string,
292	  now: string,
293	): void {
294	  writeEvent(db, {
295	    ts: now,
296	    workflowId: p.workflowId,
297	    itemId: p.itemId,
298	    sessionId: p.sessionId,
299	    stage: p.stage,
300	    phase: p.phase,
301	    attempt: p.attempt,
302	    eventType: 'prepost.revisit',
303	    level: 'info',
304	    message: `goto to phase "${destination}"`,
305	    extra: JSON.stringify({ destination }),
306	  });
307	}
