309	// ---------------------------------------------------------------------------
310	// Internal: check all depends_on are complete
311	// ---------------------------------------------------------------------------
312	
313	function checkAllDepsComplete(db: SqliteDb, item: ItemRow): boolean {
314	  if (!item.depends_on) return true;
315	  let deps: string[];
316	  try {
317	    deps = JSON.parse(item.depends_on) as string[];
318	  } catch {
319	    return false;
320	  }
321	  if (deps.length === 0) return true;
322	  const placeholders = deps.map(() => '?').join(',');
323	  const rows = db
324	    .prepare(`SELECT status FROM items WHERE id IN (${placeholders})`)
325	    .all(...deps) as { status: string }[];
326	  return rows.length === deps.length && rows.every(r => r.status === 'complete');
327	}
