329	// ---------------------------------------------------------------------------
330	// Internal: compute retry decision from item + ctx
331	// ---------------------------------------------------------------------------
332	
333	type RetryOutcome =
334	  | { kind: 'retry'; mode: Exclude<RetryMode, 'awaiting_user'>; nextRetryCount: number }
335	  | { kind: 'exhausted' };
336	
337	function computeRetry(item: ItemRow, ctx: GuardContext): RetryOutcome {
338	  return computeRetryDecision({
339	    retryCount: item.retry_count,
340	    maxOuterRetries: ctx.maxOuterRetries ?? DEFAULT_MAX_OUTER_RETRIES,
341	    retryLadder: ctx.retryLadder ?? DEFAULT_RETRY_LADDER,
342	  });
343	}
344	
345	// ---------------------------------------------------------------------------
346	// Internal: select the concrete outcome for a conditional transition
347	// ---------------------------------------------------------------------------
348	
349	/** States that trigger cascade-blocking of dependents (AC-2). */
350	const CASCADE_TRIGGER_STATES = new Set<State>(['awaiting_user', 'blocked', 'abandoned']);
351	
352	/** States where an item is terminal for stage-completion purposes (AC-1). */
353	const STAGE_TERMINAL_STATES = new Set<string>(['complete', 'blocked', 'abandoned']);
354	
355	interface OutcomeSelection {
356	  to: State;
357	  sideEffects: readonly string[];
358	  newRetryCount?: number;
359	  retryMode?: Exclude<RetryMode, 'awaiting_user'>;
360	  newPhase?: string;
361	}
362	
363	/**
364	 * Evaluate guards for a conditional TransitionResult and return the
365	 * concrete outcome.
366	 *
367	 * This function is the authoritative guard implementation for every
368	 * conditional (State × Event) pair.  The TRANSITIONS table provides the
369	 * documented outcomes; this function implements the guards that select one.
370	 *
371	 * Called only from within a db.transaction() callback, so the db parameter
372	 * is the raw writer connection (safe to read from).
373	 */
374	function selectConditionalOutcome(
375	  result: { outcomes: readonly { to: State; guard: string; sideEffects: readonly string[] }[] },
376	  currentState: State,
377	  event: Event,
378	  item: ItemRow,
379	  workflow: WorkflowRow,
380	  db: SqliteDb,
381	  ctx: GuardContext,
382	  now: string,
383	  correlationParams: {
384	    workflowId: string;
385	    itemId: string;
386	    sessionId: string | null;
387	    stage: string;
388	    phase: string;
389	    attempt: number;
390	  },
391	): OutcomeSelection {
392	  const o = result.outcomes;
393	
394	  switch (`${currentState}:${event}`) {
395	    // -----------------------------------------------------------------------
396	    // pending → deps_satisfied
397	    // Guard: all depends_on items have status = 'complete'
398	    // -----------------------------------------------------------------------
399	    case 'pending:deps_satisfied': {
400	      if (checkAllDepsComplete(db, item)) {
401	        // o[0]: all deps complete → ready
402	        return { to: o[0].to, sideEffects: o[0].sideEffects };
403	      }
404	      // Guard failed: deps not yet complete → no-op (return current state)
405	      return { to: currentState, sideEffects: [] };
406	    }
407	
408	    // -----------------------------------------------------------------------
409	    // ready → phase_start
410	    // Guard: worktree_path null → bootstrapping; else → in_progress
411	    // -----------------------------------------------------------------------
412	    case 'ready:phase_start': {
413	      const idx = workflow.worktree_path == null ? 0 : 1;
414	      return { to: o[idx].to, sideEffects: o[idx].sideEffects };
415	    }
416	
417	    // -----------------------------------------------------------------------
418	    // in_progress → pre_command_failed
419	    // Guard: action kind + retry budget
420	    // -----------------------------------------------------------------------
421	    case 'in_progress:pre_command_failed': {
422	      const action = ctx.preCommandAction ?? 'fail';
423	      if (action === 'stop-and-ask') {
424	        // o[2]: stop-and-ask → awaiting_user
425	        return { to: o[2].to, sideEffects: o[2].sideEffects };
426	      }
427	      // action = 'fail' — check retry budget
428	      const decision = computeRetry(item, ctx);
429	      if (decision.kind === 'retry') {
430	        // o[0]: fail + budget > 0 → awaiting_retry
431	        return {
432	          to: o[0].to,
433	          sideEffects: o[0].sideEffects,
434	          newRetryCount: decision.nextRetryCount,
435	          retryMode: decision.mode,
436	        };
437	      }
438	      // o[1]: fail + exhausted → awaiting_user
439	      return { to: o[1].to, sideEffects: o[1].sideEffects };
440	    }
441	
442	    // -----------------------------------------------------------------------
443	    // in_progress → session_ok
444	    // Guard: validatorsOk ∧ diffCheckOk ∧ allPostCommandsOk ∧ morePhases?
445	    // -----------------------------------------------------------------------
446	    case 'in_progress:session_ok': {
447	      const morePhases = ctx.morePhases ?? false;
448	      const idx = morePhases ? 0 : 1;
449	      // o[0]: more phases → in_progress (advance current_phase)
450	      // o[1]: last phase  → complete
451	      const newPhase = morePhases ? (ctx.nextPhase ?? item.current_phase ?? undefined) : undefined;
452	      return { to: o[idx].to, sideEffects: o[idx].sideEffects, newPhase };
453	    }
454	
455	    // -----------------------------------------------------------------------
456	    // in_progress → post_command_action
457	    // Guard: action kind, morePhases, revisit count
458	    //   o[0]: continue + more phases  → in_progress
459	    //   o[1]: continue + last phase   → complete
460	    //   o[2]: goto + within limit     → in_progress
461	    //   o[3]: goto + limit exceeded   → awaiting_user
462	    //   o[4]: retry                   → awaiting_retry
463	    //   o[5]: stop-and-ask            → awaiting_user
464	    //   o[6]: stop                    → abandoned
465	    //   o[7]: fail + budget > 0       → awaiting_retry
466	    //   o[8]: fail + exhausted        → awaiting_user
467	    // -----------------------------------------------------------------------
468	    case 'in_progress:post_command_action': {
469	      const action = ctx.postCommandAction;
470	      if (!action) {
471	        throw new Error(
472	          'post_command_action event requires guardCtx.postCommandAction',
473	        );
474	      }
475	      const morePhases = ctx.morePhases ?? false;
476	
477	      if (action.kind === 'continue') {
478	        const idx = morePhases ? 0 : 1;
479	        const newPhase =
480	          morePhases ? (ctx.nextPhase ?? item.current_phase ?? undefined) : undefined;
481	        return { to: o[idx].to, sideEffects: o[idx].sideEffects, newPhase };
482	      }
483	
484	      if (action.kind === 'goto' && action.goto) {
485	        const destination = action.goto;
486	        const maxRevisits = action.maxRevisits ?? 3;
487	        const existingCount = countRevisitEvents(db, correlationParams.itemId, destination);
488	        if (existingCount + 1 > maxRevisits) {
489	          // o[3]: limit exceeded → awaiting_user (RC-3)
490	          return { to: o[3].to, sideEffects: o[3].sideEffects };
491	        }
492	        // Insert revisit tracking event inside same transaction
493	        insertRevisitEvent(db, correlationParams, destination, now);
494	        // o[2]: within limit → in_progress
495	        return { to: o[2].to, sideEffects: o[2].sideEffects, newPhase: destination };
496	      }
497	
498	      if (action.kind === 'retry') {
499	        const decision = computeRetry(item, ctx);

500	        const decision = computeRetry(item, ctx);
501	        if (decision.kind === 'retry') {
502	          // o[4]: retry + budget → awaiting_retry
503	          return {
504	            to: o[4].to,
505	            sideEffects: o[4].sideEffects,
506	            newRetryCount: decision.nextRetryCount,
507	            retryMode: decision.mode,
508	          };
509	        }
510	        // Exhausted: use awaiting_user (o[5] is stop-and-ask, so fall through)
511	        return { to: 'awaiting_user', sideEffects: [] };
512	      }
513	
514	      if (action.kind === 'stop-and-ask') {
515	        // o[5]: stop-and-ask → awaiting_user
516	        return { to: o[5].to, sideEffects: o[5].sideEffects };
517	      }
518	
519	      if (action.kind === 'stop') {
520	        // o[6]: stop → abandoned
521	        return { to: o[6].to, sideEffects: o[6].sideEffects };
522	      }
523	
524	      if (action.kind === 'fail') {
525	        const decision = computeRetry(item, ctx);
526	        if (decision.kind === 'retry') {
527	          // o[7]: fail + budget → awaiting_retry
528	          return {
529	            to: o[7].to,
530	            sideEffects: o[7].sideEffects,
531	            newRetryCount: decision.nextRetryCount,
532	            retryMode: decision.mode,
533	          };
534	        }
535	        // o[8]: fail + exhausted → awaiting_user
536	        return { to: o[8].to, sideEffects: o[8].sideEffects };
537	      }
538	
539	      throw new Error(`Unhandled post_command_action kind: ${action.kind}`);
540	    }
541	
542	    // -----------------------------------------------------------------------
543	    // in_progress → validator_fail
544	    // Guard: retry budget > 0
545	    // -----------------------------------------------------------------------
546	    case 'in_progress:validator_fail': {
547	      const decision = computeRetry(item, ctx);
548	      if (decision.kind === 'retry') {
549	        // o[0]: budget > 0 → awaiting_retry
550	        return {
551	          to: o[0].to,
552	          sideEffects: o[0].sideEffects,
553	          newRetryCount: decision.nextRetryCount,
554	          retryMode: decision.mode,
555	        };
556	      }
557	      return { to: 'awaiting_user', sideEffects: [] };
558	    }
559	
560	    // -----------------------------------------------------------------------
561	    // in_progress → diff_check_fail
562	    // Guard: retry budget > 0 (classifier = policy implicit)
563	    // -----------------------------------------------------------------------
564	    case 'in_progress:diff_check_fail': {
565	      const decision = computeRetry(item, ctx);
566	      if (decision.kind === 'retry') {
567	        // o[0]: budget > 0 → awaiting_retry
568	        return {
569	          to: o[0].to,
570	          sideEffects: o[0].sideEffects,
571	          newRetryCount: decision.nextRetryCount,
572	          retryMode: decision.mode,
573	        };
574	      }
575	      return { to: 'awaiting_user', sideEffects: [] };
576	    }
577	
578	    // -----------------------------------------------------------------------
579	    // in_progress → session_fail
580	    // Guard: classifier result + retry budget
581	    //   o[0]: transient + budget > 0 → awaiting_retry
582	    //   o[1]: permanent              → awaiting_user
583	    //   o[2]: unknown                → awaiting_user
584	    // -----------------------------------------------------------------------
585	    case 'in_progress:session_fail': {
586	      const classifier = ctx.classifierResult ?? 'unknown';
587	      if (classifier === 'transient') {
588	        const decision = computeRetry(item, ctx);
589	        if (decision.kind === 'retry') {
590	          return {
591	            to: o[0].to,
592	            sideEffects: o[0].sideEffects,
593	            newRetryCount: decision.nextRetryCount,
594	            retryMode: decision.mode,
595	          };
596	        }
597	        // Budget exhausted even though transient — treat as retries_exhausted
598	        return { to: 'awaiting_user', sideEffects: [] };
599	      }
600	      if (classifier === 'permanent') {
601	        return { to: o[1].to, sideEffects: o[1].sideEffects };
602	      }
603	      // unknown / policy → awaiting_user (safe default, D07)
604	      return { to: o[2].to, sideEffects: o[2].sideEffects };
605	    }
606	
607	    // -----------------------------------------------------------------------
608	    // awaiting_retry → backoff_elapsed
609	    // Guard: retry budget remaining
610	    // -----------------------------------------------------------------------
611	    case 'awaiting_retry:backoff_elapsed': {
612	      const maxOuter = ctx.maxOuterRetries ?? DEFAULT_MAX_OUTER_RETRIES;
613	      const ladder = ctx.retryLadder ?? DEFAULT_RETRY_LADDER;
614	      // retry_count was already incremented when we entered awaiting_retry.
615	      // The mode for the upcoming session is the one that was chosen then.
616	      // If the caller stored it in guardCtx.currentRetryMode, use that;
617	      // otherwise re-derive from ladder[retry_count - 1].
618	      if (item.retry_count <= 0 || item.retry_count > maxOuter) {
619	        return { to: 'awaiting_user', sideEffects: [] };
620	      }
621	      const retryMode: RetryMode =
622	        ctx.currentRetryMode ??
623	        (ladder[item.retry_count - 1] ?? 'awaiting_user');
624	      if (retryMode === 'awaiting_user') {
625	        return { to: 'awaiting_user', sideEffects: [] };
626	      }
627	      return {
628	        to: o[0].to,
629	        sideEffects: o[0].sideEffects,
630	        retryMode: retryMode as Exclude<RetryMode, 'awaiting_user'>,
631	      };
632	    }
633	
634	    default:
635	      throw new Error(
636	        `Unhandled conditional transition guard for (${currentState}, ${event})`,
637	      );
638	  }
639	}
