641	// ---------------------------------------------------------------------------
642	// Internal: cascade-block dependents (BFS, within an existing transaction)
643	// ---------------------------------------------------------------------------
644	
645	/**
646	 * Cascade-blocks all transitive dependents of the given item (AC-2).
647	 *
648	 * Must be called from within a db.transaction() callback.  Takes the raw
649	 * writer connection so it participates in the same SQLite transaction.
650	 *
651	 * Items already in terminal states (complete, blocked, abandoned) are
652	 * skipped silently.
653	 */
654	function cascadeBlockDependents(
655	  db: SqliteDb,
656	  workflowId: string,
657	  originItemId: string,
658	  blockedReason: string,
659	  now: string,
660	): void {
661	  const visited = new Set<string>([originItemId]);
662	  const queue: string[] = [originItemId];
663	
664	  while (queue.length > 0) {
665	    const parentId = queue.shift()!;
666	
667	    // Find items in this workflow whose depends_on includes parentId
668	    const directDependents = db
669	      .prepare(`
670	        SELECT id, status FROM items
671	         WHERE workflow_id = ?
672	           AND depends_on IS NOT NULL
673	           AND EXISTS (
674	             SELECT 1 FROM json_each(depends_on) je WHERE je.value = ?
675	           )
676	      `)
677	      .all(workflowId, parentId) as { id: string; status: string }[];
678	
679	    for (const dep of directDependents) {
680	      if (visited.has(dep.id)) continue;
681	      visited.add(dep.id);
682	
683	      // Skip items already in a terminal state
684	      if (STAGE_TERMINAL_STATES.has(dep.status)) continue;
685	
686	      // Block this dependent
687	      db.prepare(`
688	        UPDATE items
689	           SET status = 'blocked',
690	               blocked_reason = ?,
691	               updated_at = ?
692	         WHERE id = ?
693	      `).run(blockedReason, now, dep.id);
694	
695	      writeEvent(db, {
696	        ts: now,
697	        workflowId,
698	        itemId: dep.id,
699	        sessionId: null,
700	        stage: null,
701	        phase: null,
702	        attempt: null,
703	        eventType: 'cascade_block',
704	        level: 'info',
705	        message: `Cascade-blocked by ${originItemId}: ${blockedReason}`,
706	        extra: JSON.stringify({ origin: originItemId, reason: blockedReason }),
707	      });
708	
709	      // Continue BFS for this newly-blocked item's own dependents
710	      queue.push(dep.id);
711	    }
712	  }
713	}
