950	// ---------------------------------------------------------------------------
951	// checkStageComplete — public
952	// ---------------------------------------------------------------------------
953	
954	/** Terminal states for stage-completion purposes (AC-1). */
955	const TERMINAL_FOR_STAGE = ['complete', 'blocked', 'abandoned'];
956	
957	/**
958	 * Check whether all items in a stage have reached a terminal state.
959	 *
960	 * A stage is complete when every item's status ∈ {complete, blocked,
961	 * abandoned} (AC-1). A single non-terminal item prevents advancement.
962	 *
963	 * Re-reads SQLite on every call (RC-1: no caching).
964	 *
965	 * @returns true if ALL items in the stage are terminal, false otherwise.
966	 *          Returns false if there are no items in the stage.
967	 */
968	export function checkStageComplete(
969	  db: DbPool,
970	  workflowId: string,
971	  stageId: string,
972	): boolean {
973	  return checkStageCompleteInTxn(db.reader(), workflowId, stageId);
974	}
975	
976	/** Same as checkStageComplete but takes a raw connection (for use within txn). */
977	function checkStageCompleteInTxn(
978	  db: SqliteDb,
979	  workflowId: string,
980	  stageId: string,
981	): boolean {
982	  const row = db
983	    .prepare(`
984	      SELECT
985	        COUNT(*) AS total,
986	        SUM(CASE WHEN status IN ('complete','blocked','abandoned') THEN 1 ELSE 0 END) AS terminal
987	      FROM items
988	      WHERE workflow_id = ? AND stage_id = ?
989	    `)
990	    .get(workflowId, stageId) as { total: number; terminal: number | null };
991	
992	  const { total, terminal } = row;
993	  return total > 0 && (terminal ?? 0) >= total;
994	}
