997	// buildCrashRecovery — public
998	// ---------------------------------------------------------------------------
999

1000	export interface StaleSession {
1001	  sessionId: string;
1002	  itemId: string | null;
1003	  phase: string;
1004	  pid: number;
1005	  pgid: number | null;
1006	}
1007	
1008	/** @deprecated Use StaleSession — kept for one release to avoid breaking callers. */
1009	export type StaleSesssion = StaleSession;
1010	
1011	export interface WorkflowRecoveryInfo {
1012	  workflowId: string;
1013	  staleSessions: StaleSession[];
1014	  detectedAt: string;
1015	}
1016	
1017	/**
1018	 * Rebuild the crash-recovery projection from SQLite on startup (AC-4).
1019	 *
1020	 * For each non-terminal workflow, finds sessions with status='running' and
1021	 * a non-null PID.  Probes each PID with kill(pid, 0): ESRCH means the
1022	 * process is gone (stale).
1023	 *
1024	 * For workflows with stale sessions, sets recovery_state JSON on the
1025	 * workflows row.  Does NOT apply any item-state transitions (AC-4 /RC-2:
1026	 * "no auto-transition; user_retry or auto_resume fires the normal row").
1027	 *
1028	 * @returns list of workflows affected (recovery_state written).
1029	 */
1030	export function buildCrashRecovery(db: DbPool): WorkflowRecoveryInfo[] {
1031	  const now = new Date().toISOString();
1032	
1033	  // Non-terminal workflow statuses: anything not in the three terminal labels.
1034	  const TERMINAL_WF_STATUSES = ['completed', 'abandoned', 'completed_with_blocked'];
1035	  const placeholders = TERMINAL_WF_STATUSES.map(() => '?').join(',');
1036	
1037	  const workflows = db.writer
1038	    .prepare(
1039	      `SELECT id FROM workflows WHERE status NOT IN (${placeholders})`,
1040	    )
1041	    .all(...TERMINAL_WF_STATUSES) as { id: string }[];
1042	
1043	  // --- Phase 1: probe PIDs outside SQLite (system calls, no DB state) -------
1044	  // Collect WorkflowRecoveryInfo for every workflow that has stale sessions.
1045	  // PID probes are intentionally outside the transaction so that a long probe
1046	  // loop does not hold a write lock on the DB.
1047	  const toWrite: WorkflowRecoveryInfo[] = [];
1048	
1049	  for (const wf of workflows) {
1050	    const runningSessions = db.writer
1051	      .prepare(`
1052	        SELECT id, item_id, phase, pid, pgid
1053	          FROM sessions
1054	         WHERE workflow_id = ?
1055	           AND status = 'running'
1056	           AND pid IS NOT NULL
1057	      `)
1058	      .all(wf.id) as SessionRunRow[];
1059	
1060	    const stale: StaleSession[] = [];
1061	
1062	    for (const sess of runningSessions) {
1063	      if (sess.pid == null) continue;
1064	      if (!probeProcess(sess.pid)) {
1065	        stale.push({
1066	          sessionId: sess.id,
1067	          itemId: sess.item_id,
1068	          phase: sess.phase,
1069	          pid: sess.pid,
1070	          pgid: sess.pgid,
1071	        });
1072	      }
1073	    }
1074	
1075	    if (stale.length > 0) {
1076	      toWrite.push({ workflowId: wf.id, staleSessions: stale, detectedAt: now });
1077	    }
1078	  }
1079	
1080	  if (toWrite.length === 0) return [];
1081	
1082	  // --- Phase 2: commit all recovery_state writes in ONE transaction ---------
1083	  // All-or-nothing: a crash mid-loop no longer leaves some workflows with
1084	  // recovery_state written and others not (non-blocking review feedback).
1085	  db.transaction((writer) => {
1086	    const stmt = writer.prepare(
1087	      `UPDATE workflows SET recovery_state = ?, updated_at = ? WHERE id = ?`,
1088	    );
1089	    for (const info of toWrite) {
1090	      stmt.run(JSON.stringify(info), now, info.workflowId);
1091	    }
1092	  });
1093	
1094	  return toWrite;
1095	}
