1151	// ---------------------------------------------------------------------------
1152	// Internal: PID liveness probe (kill(pid, 0))
1153	// ---------------------------------------------------------------------------
1154	
1155	/**
1156	 * Probe whether a PID is alive using signal 0.
1157	 *
1158	 * `process.kill(pid, 0)` throws ESRCH if the process does not exist.
1159	 * On macOS/Linux, EPERM means the process exists but we lack permission
1160	 * to signal it (still alive from our perspective).
1161	 *
1162	 * @returns true if the process appears alive, false if it is gone.
1163	 */
1164	function probeProcess(pid: number): boolean {
1165	  try {
1166	    process.kill(pid, 0);
1167	    return true;
1168	  } catch (err: unknown) {
1169	    const e = err as NodeJS.ErrnoException;
1170	    // EPERM: process exists but we can't signal it → alive
1171	    if (e.code === 'EPERM') return true;
1172	    // ESRCH: no such process → stale
1173	    return false;
1174	  }
1175	}
