28	
29	// ---------------------------------------------------------------------------
30	// Helpers
31	// ---------------------------------------------------------------------------
32	
33	/** Path to the migrations directory, resolved relative to this source file. */
34	function migrationsDir(): string {
35	  const here = path.dirname(fileURLToPath(import.meta.url));
36	  return path.resolve(here, '../server/storage/migrations');
37	}
