39	// ---------------------------------------------------------------------------
40	// Public API (exported for testing)
41	// ---------------------------------------------------------------------------
42	
43	export interface StartOptions {
44	  /** Path to the .yoke.yml config file. Default: <cwd>/.yoke.yml */
45	  configPath?: string;
46	  /** Server port. Default: 7777 */
47	  port?: number;
48	}
49	
50	export interface StartHandle {
51	  url: string;
52	  db: DbPool;
53	  fastify: FastifyInstance;
54	  /** Clean shutdown: closes db + fastify. */
55	  close(): Promise<void>;
56	}
