58	/**
59	 * Validate config, open DB, run migrations, start Fastify, return a handle.
60	 * Throws on config validation failure (caller should exit non-zero).
61	 * Exported for integration tests.
62	 */
63	export async function startServer(opts: StartOptions = {}): Promise<StartHandle> {
64	  const configPath = opts.configPath ?? path.join(process.cwd(), '.yoke.yml');
65	  const port = opts.port ?? 7777;
66	
67	  // Load + validate config — throws ConfigLoadError on failure.
68	  const config = loadConfig(configPath);
69	
70	  // Database lives under .yoke/ in the config directory.
71	  const yokeDir = path.join(config.configDir, '.yoke');
72	  fs.mkdirSync(yokeDir, { recursive: true });
73	  const dbPath = path.join(yokeDir, 'yoke.db');
74	
75	  const db = openDbPool(dbPath);
76	  applyMigrations(db.writer, migrationsDir());
77	
78	  // Start server.
79	  const fastify = await listenServer(db, { port });
80	
81	  const addr = fastify.server.address();
82	  const actualPort = typeof addr === 'object' && addr !== null ? addr.port : port;
83	  const url = `http://127.0.0.1:${actualPort}`;
84	
85	  // Write server discovery file.
86	  const serverJson = path.join(yokeDir, 'server.json');
87	  fs.writeFileSync(serverJson, JSON.stringify({ url, pid: process.pid }), 'utf8');
88	
89	  return {
90	    url,
91	    db,
92	    fastify,
93	    async close() {
94	      await fastify.close();
95	      db.close();
96	      // Remove discovery file on clean shutdown.
97	      try {
98	        fs.unlinkSync(serverJson);
99	      } catch {
100	        // Not fatal if already removed.
101	      }
102	    },
103	  };
104	}
