107	// Commander registration
108	// ---------------------------------------------------------------------------
109	
110	export function register(program: Command): void {
111	  program
112	    .command('start')
113	    .description('Start the Yoke pipeline engine')
114	    .option('-c, --config <path>', 'Path to .yoke.yml', '.yoke.yml')
115	    .option('-p, --port <number>', 'Server port', '7777')
116	    .action(async (opts: { config: string; port: string }) => {
117	      const configPath = path.resolve(opts.config);
118	      const port = parseInt(opts.port, 10);
119	
120	      let handle: StartHandle;
121	      try {
122	        handle = await startServer({ configPath, port });
123	      } catch (err) {
124	        if (err instanceof ConfigLoadError) {
125	          console.error(`Configuration error: ${err.message}`);
126	          process.exit(1);
127	        }
128	        throw err;
129	      }
130	
131	      console.log(`Yoke server running at ${handle.url}`);
132	
133	      // Keep process alive. SIGINT / SIGTERM → graceful shutdown.
134	      async function shutdown(signal: string): Promise<never> {
135	        console.log(`\n${signal} received — shutting down...`);
136	        await handle.close();
137	        process.exit(0);
138	      }
139	
140	      process.on('SIGINT', () => void shutdown('SIGINT'));
141	      process.on('SIGTERM', () => void shutdown('SIGTERM'));
142	    });
143	}
