175	
176	    // RC-4: validate path is absolute and strictly under baseDir.
177	    this._validateWorktreePath(worktreePath, baseDir);
178	
179	    // Ensure the base directory exists before git worktree add creates the subdir.
180	    fs.mkdirSync(path.resolve(baseDir), { recursive: true });
181	
182	    // 'git worktree add -b <branch> <path>' creates the branch at HEAD and
183	    // checks it out in the new worktree directory in one atomic git operation.
184	    try {
185	      await execFileAsync('git', [
186	        '-C', this.repoRoot,
187	        'worktree', 'add',
188	        '-b', branchName,
189	        worktreePath,
190	      ]);
191	    } catch (err) {
192	      throw new WorktreeError(
193	        'git_error',
194	        `Failed to create worktree '${worktreePath}' on branch '${branchName}': ${(err as Error).message}`,
195	        err,
196	      );
197	    }
198	
199	    return { branchName, worktreePath };
200	  }
201	
202	  // -------------------------------------------------------------------------
203	  // runBootstrap — AC-2, AC-3, RC-1
204	  // -------------------------------------------------------------------------
205	
206	  /**
207	   * Runs bootstrap.commands in declared order as a state-machine phase (RC-1).
208	   *
209	   * Returns a BootstrapEvent for the Pipeline Engine to consume:
210	   *   bootstrap_ok   — all commands exited 0.
211	   *   bootstrap_fail — a command exited non-zero; subsequent commands are skipped.
212	   *
213	   * The returned event type is what the Pipeline Engine passes to applyItemTransition():
214	   *   applyItemTransition({ event: event.type, ... })
215	   * This method does NOT write to SQLite — the Pipeline Engine is the sole SQLite
216	   * mutator (AC-5).  The bootstrap_fail transition already carries the
217	   * 'insert pending_attention{kind=bootstrap_failed}' side-effect label in the
218	   * TRANSITIONS table, so the engine handles that write.
219	   *
220	   * This module never calls transition() itself (RC-1).
221	   *
222	   * AC-3 (bootstrap_failed never auto-cleans) is enforced by the state machine:
223	   * the Pipeline Engine only calls cleanup() on transitions that lead to
224	   * cleanup side effects; bootstrap_failed has no such transition.
225	   */
226	  async runBootstrap(opts: RunBootstrapOpts): Promise<BootstrapEvent> {
227	    const { worktreePath, commands } = opts;
228	
229	    for (const cmd of commands) {
230	      const result = await this._runShellCommand(cmd, worktreePath);
231	
232	      if (result.exitCode !== 0) {
233	        return {
234	          type: 'bootstrap_fail',
235	          failedCommand: cmd,
236	          exitCode: result.exitCode ?? 1,
237	          stderr: result.stderr,
238	        };
239	      }
240	    }
241	
242	    return { type: 'bootstrap_ok' };
243	  }
244	
245	  // -------------------------------------------------------------------------
246	  // runTeardown — AC-4
247	  // -------------------------------------------------------------------------
248	
249	  /**
250	   * Invokes .yoke/teardown.sh in the worktree directory, if it exists.
251	   *
252	   * Absence of the script is NOT an error (AC-4). A non-zero exit is
253	   * treated as non-fatal: a warning is logged and cleanup continues.
254	   * This mirrors the semantics described in plan-draft3 §Worktree Management:
255	   * teardown stops containers and closes sockets — failure should not prevent
256	   * the worktree from being removed.
257	   */
258	  async runTeardown(worktreePath: string): Promise<void> {
259	    const teardownScript = path.join(worktreePath, '.yoke', 'teardown.sh');
260	
261	    if (!fs.existsSync(teardownScript)) {
262	      return; // Absence is not an error (AC-4).
263	    }
264	
265	    try {
266	      await execFileAsync('sh', [teardownScript], { cwd: worktreePath });
267	    } catch {
268	      // Non-zero exit from teardown.sh is non-fatal — log a warning and
269	      // continue cleanup so the worktree is still removed.
270	      console.warn(
271	        `[worktree] .yoke/teardown.sh exited non-zero in '${worktreePath}'; continuing cleanup`,
272	      );
273	    }
274	  }
275	
276	  // -------------------------------------------------------------------------
277	  // cleanup — AC-4, AC-5, AC-6, RC-2, RC-3
278	  // -------------------------------------------------------------------------
279	
280	  /**
281	   * Performs ordered worktree cleanup:
282	   *
283	   *   Pre-check — refuse cleanup if branch has unpushed commits without a PR
284	   *               (AC-5). Logs a warning and returns without destructive action.
285	   *
286	   *   Step 1    — kill tracked pids (SIGTERM → gracePeriodMs → SIGKILL).
287	   *   Step 2    — run .yoke/teardown.sh if present (AC-4).
288	   *   Step 3    — git worktree remove --force (RC-3: only after teardown).
289	   *   Step 4    — branch retention decision (v1: keep branch by default).
290	   *
291	   * @throws {WorktreeError} kind='git_error' if git worktree remove fails.
292	   */
293	  async cleanup(opts: CleanupOpts): Promise<CleanupResult> {
294	    const { worktreePath, branchName, trackedPids, gracePeriodMs = 10_000 } = opts;
295	
296	    // Pre-check: branch retention guard (AC-5, RC-2).
297	    // _hasUnpushedCommits reads the git remote state (not just local refs).
298	    const hasUnpushed = await this._hasUnpushedCommits(branchName);
299	    if (hasUnpushed) {
300	      const prExists = await this.checkPrFn(branchName, this.repoRoot);
301	      if (!prExists) {
302	        console.warn(
303	          `[worktree] auto-cleanup refused for branch '${branchName}': ` +
304	            'branch has unpushed commits and no open PR was found. ' +
305	            "Push the branch or create a PR before cleanup, or use 'yoke cancel' to force.",
306	        );
307	        return { worktreeRemoved: false, branchRetained: true, refusedReason: 'unpushed_commits_no_pr' };
308	      }
309	    }
310	
311	    // Step 1: Kill tracked pids (SIGTERM → SIGKILL escalation).
312	    for (const pid of trackedPids) {
313	      await killProcessGroup(pid, gracePeriodMs);
314	    }
315	
316	    // Step 2: Teardown hook (AC-4); must complete before git worktree remove (RC-3).
317	    await this.runTeardown(worktreePath);
318	
319	    // Step 3: git worktree remove --force.
320	    // '--force' is used only here — AFTER teardown has run (RC-3).
321	    try {
322	      await execFileAsync('git', [
323	        '-C', this.repoRoot,
324	        'worktree', 'remove', '--force', worktreePath,
325	      ]);
326	    } catch (err) {
327	      throw new WorktreeError(
328	        'git_error',
329	        `Failed to remove worktree '${worktreePath}': ${(err as Error).message}`,
330	        err,
331	      );
332	    }
333	
334	    // Step 4: Branch retention decision.
335	    // v1: retain the branch after worktree removal. The branch is still
336	    // accessible via 'git checkout yoke/<name>-<shortid>' for inspection.
337	    // Branch deletion (e.g. after merge) is out of v1 scope per plan-draft3
338	    // §Worktree Management (D40 §Rules).
339	
340	    return { worktreeRemoved: true, branchRetained: false };
341	  }
342	
343	  // -------------------------------------------------------------------------
344	  // Private helpers
345	  // -------------------------------------------------------------------------
346	
347	  /**
348	   * Validates that worktreePath:
349	   *   1. Is an absolute path.
350	   *   2. Is strictly under baseDir (no '..' traversal escapes).
351	   *
352	   * RC-4: every worktree is confined to the user-configured baseDir.
353	   */
354	  private _validateWorktreePath(worktreePath: string, baseDir: string): void {
355	    if (!path.isAbsolute(worktreePath)) {
356	      throw new WorktreeError(
357	        'invalid_path',
358	        `Worktree path must be absolute; got: '${worktreePath}'`,
359	      );
360	    }
361	
362	    const canonicalBase = path.resolve(baseDir);
363	    const canonicalWorktree = path.resolve(worktreePath);
364	
365	    // The resolved path must START with baseDir + sep to prevent:
366	    //   - A path that equals baseDir itself (not a subdirectory).
367	    //   - A path that starts with baseDir but then has a different continuation
368	    //     after a symlink (not a concern here since we use resolve).
369	    if (!canonicalWorktree.startsWith(canonicalBase + path.sep)) {
370	      throw new WorktreeError(
371	        'path_traversal',
372	        `Worktree path '${worktreePath}' is not under base directory '${baseDir}'`,
373	      );
374	    }
375	  }
376	
377	  /**
378	   * Runs a single shell command string (from bootstrap.commands or teardown).
379	   *
380	   * Uses 'sh -c <cmd>' so commands like 'pnpm install' or 'docker compose up -d'
381	   * work without needing argv-splitting. The .yoke.yml is user-authored and
382	   * trusted per the architecture threat model.
383	   *
384	   * Captures stderr (capped at 4 KB). Returns exit code and stderr string.
385	   * Never throws — spawn failures are represented as { exitCode: 1 }.
386	   */
387	  private async _runShellCommand(
388	    cmd: string,
389	    cwd: string,
390	  ): Promise<{ exitCode: number | null; stderr: string }> {
391	    try {
392	      await execFileAsync('sh', ['-c', cmd], {
393	        cwd,
394	        env: { ...process.env },
395	        maxBuffer: 4 * 1024 * 1024, // 4 MB stdout/stderr buffer
396	      });
397	      return { exitCode: 0, stderr: '' };
398	    } catch (err: unknown) {
399	      // execFileAsync rejects with an error that carries .code (exit code)
400	      // and .stderr (captured stderr string) when the command exits non-zero.
401	      // When sh itself cannot be spawned, .code is a string like 'ENOENT'.
402	      const e = err as { code?: unknown; stderr?: unknown };
403	      const exitCode = typeof e.code === 'number' ? e.code : 1;
404	      const rawStderr = typeof e.stderr === 'string' ? e.stderr : '';
405	      return { exitCode, stderr: rawStderr.slice(0, 4096) };
406	    }
407	  }
408	
409	  /**
410	   * Checks whether the branch has commits not present on any remote tracking
411	   * branch (RC-2: reads git remote state, not just local refs).
412	   *
413	   * Uses 'git log <branch> --not --remotes --oneline':
414	   *   - Empty output → all commits are on a remote → false.
415	   *   - Non-empty output → unpushed commits exist → true.
416	   *
417	   * If no remote is configured, '--remotes' is empty so '--not --remotes'
418	   * filters nothing: all commits appear as "unpushed." This is the
419	   * conservative direction — refuse cleanup unless a PR exists.
420	   *
421	   * Returns false on git command failure (e.g. branch does not yet exist)
422	   * so cleanup of invalid/pre-push branches is not blocked.
423	   */
424	  private async _hasUnpushedCommits(branchName: string): Promise<boolean> {
425	    try {
426	      const { stdout } = await execFileAsync('git', [
427	        '-C', this.repoRoot,
428	        'log', branchName,
429	        '--not', '--remotes',
430	        '--oneline',
431	      ]);
432	      return stdout.trim().length > 0;
433	    } catch {
434	      // Branch may not exist yet or git is not available — treat as no
435	      // unpushed commits so cleanup of non-existent branches is not blocked.
436	      return false;
437	    }
438	  }
439	}
440	
441	// ---------------------------------------------------------------------------
442	// Default PR existence check (production implementation)
443	// ---------------------------------------------------------------------------
444	
445	/**
446	 * Checks whether a PR exists for the given branch using the 'gh' CLI.
447	 *
448	 * 'gh pr list --head <branch> --json number' returns a JSON array:
449	 *   Non-empty → PR exists → cleanup is allowed even with unpushed commits.
450	 *   Empty []  → no PR → refuse cleanup if unpushed commits are present.
451	 *
452	 * If 'gh' is not installed, not authenticated, or the remote is not GitHub,
453	 * returns false — the conservative direction (refuse cleanup).
454	 */
455	const defaultCheckPr: CheckPrFn = async (
456	  branchName: string,
457	  repoRoot: string,
458	): Promise<boolean> => {
459	  try {
460	    const { stdout } = await execFileAsync(
461	      'gh',
462	      ['pr', 'list', '--head', branchName, '--json', 'number'],
463	      { cwd: repoRoot },
464	    );
465	    const parsed = JSON.parse(stdout.trim());
466	    return Array.isArray(parsed) && parsed.length > 0;
467	  } catch {
468	    // gh not installed, not authenticated, or non-GitHub remote.
469	    // Safe direction: treat as no PR.
470	    return false;
471	  }
472	};
473	
474	// ---------------------------------------------------------------------------
475	// killProcessGroup — SIGTERM → SIGKILL escalation
476	// ---------------------------------------------------------------------------
477	
478	/**
479	 * Sends SIGTERM to the process group of `pid`, waits up to `gracePeriodMs`,
480	 * then sends SIGKILL if the process group is still alive.
481	 *
482	 * Used in cleanup step 1 to kill tracked child pids before teardown runs.
483	 *
484	 * SIGTERM is sent to -pid (the entire process group), matching the shutdown
485	 * contract in plan-draft3 §Process Management §Shutdown.
486	 */
487	async function killProcessGroup(pid: number, gracePeriodMs: number): Promise<void> {
488	  try {
489	    process.kill(-pid, 'SIGTERM');
490	  } catch {
491	    // ESRCH: process group already gone — not an error.
492	    return;
493	  }
494	
495	  return new Promise<void>((resolve) => {
496	    // Poll at 50 ms intervals to detect natural death.
497	    const poll = setInterval(() => {
498	      try {
499	        process.kill(pid, 0); // liveness probe
500	      } catch {
501	        // ESRCH: process died naturally before the grace period expired.
502	        clearInterval(poll);
503	        clearTimeout(timer);
504	        resolve();
505	      }
506	    }, 50);
507	
508	    // Escalate to SIGKILL after the grace period.
509	    const timer = setTimeout(() => {
510	      clearInterval(poll);
511	      try {
512	        process.kill(-pid, 'SIGKILL');
513	      } catch {
514	        // Process group gone between SIGTERM and SIGKILL — fine.
515	      }
516	      resolve();
517	    }, gracePeriodMs);
518	  });
519	}
