/**
 * TypeScript types for .yoke.yml configuration.
 *
 * Derived from docs/design/schemas/yoke-config.schema.json (JSON Schema draft-2020-12).
 * Version "1" is the only supported version.
 *
 * Two forms:
 *   RawConfig      — direct YAML parse output; path fields may be relative strings.
 *   ResolvedConfig — RawConfig with all path fields guaranteed to be absolute,
 *                    plus a `configDir` field. All downstream modules consume
 *                    ResolvedConfig only.
 *
 * Resolved at load time (relative → absolute, base = .yoke.yml directory):
 *   phases[*].prompt_template
 *   phases[*].cwd                          (if present)
 *   phases[*].output_artifacts[*].schema   (if present)
 *   worktrees.teardown.script              (if present)
 *
 * NOT resolved (runtime-relative to the worktree, unknown at load time):
 *   pipeline.stages[*].items_from
 *   phases[*].output_artifacts[*].path
 */

// ---------------------------------------------------------------------------
// Action grammar (mirrors docs/design/schemas/pre-post-action-grammar.md)
// ---------------------------------------------------------------------------

export type RetryMode =
  | 'continue'
  | 'fresh_with_failure_summary'
  | 'fresh_with_diff'
  | 'awaiting_user';

export type ActionValue =
  | 'continue'
  | 'stop-and-ask'
  | 'stop'
  | { goto: string; max_revisits?: number }
  | { retry: { mode: 'continue' | 'fresh_with_failure_summary' | 'fresh_with_diff'; max: number } }
  | { fail: { reason: string } };

/** Keys are exit-code strings ("0"–"255") or the wildcard "*". */
export type ActionsMap = Record<string, ActionValue>;

// ---------------------------------------------------------------------------
// Pre / post commands
// ---------------------------------------------------------------------------

export interface PrePostCommand {
  name: string;
  /** argv-form; spawned with shell: false */
  run: string[];
  timeout_s?: number;
  env?: Record<string, string>;
  actions: ActionsMap;
}

// ---------------------------------------------------------------------------
// Phase
// ---------------------------------------------------------------------------

export interface OutputArtifact {
  /** Relative to worktree (not resolved at load time). */
  path: string;
  /** Path to a JSON Schema file. Absolute in ResolvedConfig. */
  schema?: string;
  required?: boolean;
}

export interface Heartbeat {
  /**
   * Interval in seconds for the liveness probe (kill(pid, 0)).
   * Default: 30 s.
   */
  liveness_interval_s?: number;
  /** Seconds of stdout silence before the stream-activity watchdog warns. Default: 90 s. */
  activity_timeout_s?: number;
  /** Tool-name → wall-clock budget in seconds. */
  per_tool_budgets?: Record<string, number>;
}

export interface Phase {
  command: string;
  args: string[];
  env?: Record<string, string>;
  /** Absolute in ResolvedConfig (if present). */
  cwd?: string;
  /** Absolute in ResolvedConfig. */
  prompt_template: string;
  output_artifacts?: OutputArtifact[];
  max_outer_retries?: number;
  retry_ladder?: RetryMode[];
  heartbeat?: Heartbeat;
  pre?: PrePostCommand[];
  post?: PrePostCommand[];
}

// ---------------------------------------------------------------------------
// Pipeline / stages
// ---------------------------------------------------------------------------

export interface ItemsDisplay {
  title?: string;
  subtitle?: string;
}

export interface Stage {
  id: string;
  run: 'once' | 'per-item';
  /** Ordered phase keys referencing the top-level phases map. */
  phases: string[];
  needs_approval?: boolean;
  /** Relative to worktree — NOT resolved at load time. */
  items_from?: string;
  items_list?: string;
  items_id?: string;
  items_depends_on?: string;
  items_display?: ItemsDisplay;
}

export interface Pipeline {
  stages: Stage[];
}

// ---------------------------------------------------------------------------
// Top-level optional sections
// ---------------------------------------------------------------------------

export interface Project {
  name: string;
}

export interface WorktreesBootstrap {
  commands?: string[];
}

export interface WorktreesTeardown {
  /** Absolute in ResolvedConfig (if present). */
  script?: string;
}

export interface Worktrees {
  base_dir?: string;
  branch_prefix?: string;
  auto_cleanup?: boolean;
  cleanup_tool?: 'git' | 'lazyworktree' | 'custom';
  bootstrap?: WorktreesBootstrap;
  teardown?: WorktreesTeardown;
}

export interface NotificationMechanism {
  type: 'browser_push' | 'macos_native';
}

export interface Notifications {
  enabled?: boolean;
  severity_map?: Record<string, string>;
  mechanisms?: NotificationMechanism[];
}

export interface Github {
  enabled?: boolean;
  auto_pr?: boolean;
  pr_target_branch?: string;
  auth_order?: Array<'env:GITHUB_TOKEN' | 'gh:auth:token'>;
  attach_artifacts_to_pr?: boolean;
  link_issues?: boolean;
}

export type SqliteRetention = 'forever' | { max_age_days: number };

export interface RetentionStreamJsonLogs {
  max_age_days?: number;
  max_total_bytes?: number;
}

export interface Retention {
  sqlite?: SqliteRetention;
  stream_json_logs?: RetentionStreamJsonLogs;
  worktrees?: 'workflow-completion' | 'manual' | 'on-disk-pressure';
}

export interface Logging {
  retain_stream_json?: boolean;
}

export interface Runtime {
  keep_awake?: boolean;
}

export interface RateLimit {
  handling?: 'passive';
  /** v1.1 only; rejected at load time in v1 by the schema. */
  usage_pause_threshold?: number;
}

export interface Ui {
  port?: number;
  bind?: '127.0.0.1';
  auth?: false;
}

// ---------------------------------------------------------------------------
// Root config types
// ---------------------------------------------------------------------------

/**
 * Raw config as parsed from .yoke.yml — before path resolution.
 * Relative path fields are still relative strings in this type.
 */
export interface RawConfig {
  version: string;
  project: Project;
  pipeline: Pipeline;
  /** Keys are phase names referenced by pipeline stages. */
  phases: Record<string, Phase>;
  worktrees?: Worktrees;
  notifications?: Notifications;
  github?: Github;
  retention?: Retention;
  logging?: Logging;
  runtime?: Runtime;
  rate_limit?: RateLimit;
  ui?: Ui;
  safety_mode?: 'strict' | 'default' | 'yolo';
}

/**
 * Config with all relative paths resolved to absolute paths, using the
 * .yoke.yml directory as the base. All downstream modules consume only
 * this type — never RawConfig.
 */
export type ResolvedConfig = RawConfig & {
  /** Absolute path of the directory containing .yoke.yml. */
  configDir: string;
};

/**
 * PromptContext builder — assembles the context object fed to assemblePrompt().
 *
 * Responsibilities (feat-prompt-asm, prompt-template-spec.md §4):
 *   1. Read architecture.md and progress.md from the worktree (or "" if absent).
 *   2. Parse item.data as an opaque JSON blob (AC-4: no named field access).
 *   3. Project item_state from harness-state columns (status, current_phase,
 *      retry_count, blocked_reason).
 *   4. Read handoff.json and serialize its entries array as the {{handoff}} value.
 *   5. Call git.logRecent(20) for {{git_log_recent}}.
 *   6. Call git.diffRange(from, to) for {{recent_diff}} when refs are provided.
 *   7. Return a fully-populated PromptContext; every key that appears in a
 *      standard template is present (optional keys use "" for absent content).
 *
 * Non-responsibilities:
 *   - Does NOT apply state-machine transitions.
 *   - Does NOT spawn processes.
 *   - Does NOT write to SQLite.
 *
 * I/O lives here (RC-1): fs.readFileSync calls for architecture.md, progress.md,
 * and handoff.json are in this file, not in assembler.ts.
 *
 * Review criteria compliance:
 *   RC-3  item.data is parsed as an opaque blob; no harness-level field names
 *         are accessed inside this module beyond what template vars reference.
 *         The parsed object is stored whole under the "item" key.
 */

import fs from 'node:fs';
import path from 'node:path';
import type { PromptContext } from './engine.js';

// ---------------------------------------------------------------------------
// Row projections — typed wrappers over SQLite rows
// ---------------------------------------------------------------------------

/**
 * Projection of the columns from the `workflows` table that the context
 * builder reads. The caller is responsible for querying SQLite and producing
 * this plain object.
 */
export interface WorkflowRow {
  id: string;
  name: string;
  current_stage: string | null;
}

/**
 * Projection of the columns from the `items` table that the context builder
 * reads.
 *
 * `data` is an opaque JSON blob. The builder parses it and stores the whole
 * parsed object under the "item" key in PromptContext. No named fields within
 * `data` are accessed by the builder (AC-4, RC-3).
 */
export interface ItemRow {
  id: string;
  data: string;              // opaque JSON blob from SQLite TEXT column
  status: string;
  current_phase: string | null;
  retry_count: number;
  blocked_reason: string | null;
}

// ---------------------------------------------------------------------------
// ItemStateProjection — harness-tracked state surfaced to templates
// ---------------------------------------------------------------------------

/**
 * Harness-level state fields exposed as {{item_state}} in templates (Issue 3,
 * prompt-template-spec.md §3.2). These are the *harness* columns, not the
 * opaque item.data fields.
 *
 * Templates access these via:
 *   {{item_state}}                → full JSON object
 *   {{item_state.status}}         → string
 *   {{item_state.current_phase}}  → string or [MISSING:...] if null
 *   {{item_state.retry_count}}    → JSON-serialized number
 *   {{item_state.blocked_reason}} → string or [MISSING:...] if null
 */
export interface ItemStateProjection {
  status: string;
  current_phase: string | null;
  retry_count: number;
  blocked_reason: string | null;
}

// ---------------------------------------------------------------------------
// HandoffFile — typed shape of handoff.json
// ---------------------------------------------------------------------------

/**
 * Parsed shape of handoff.json written by previous phase sessions.
 * The entries array is the canonical handoff payload; the rest is metadata.
 */
export interface HandoffEntry {
  phase: string;
  attempt: number;
  ts: string;
  [key: string]: unknown;

  [key: string]: unknown;
}

export interface HandoffFile {
  feature?: string;
  entries?: HandoffEntry[];
  [key: string]: unknown;
}

// ---------------------------------------------------------------------------
// GitHelper — injected abstraction for git operations (no shell in assembler)
// ---------------------------------------------------------------------------

/**
 * Git helper interface injected into the context builder.
 *
 * The builder calls these functions; the implementation uses execFileAsync('git').
 * Injecting as a plain object enables unit testing without a real git repository.
 */
export interface GitHelper {
  /**
   * Returns the last `n` commits formatted for prompt injection.
   * Equivalent to: git log --oneline -n <n>
   */
  logRecent(n: number): Promise<string>;

  /**
   * Returns the diff between two git refs.
   * Equivalent to: git diff <from> <to>
   * Returns "" if either ref is absent.
   */
  diffRange(from: string, to: string): Promise<string>;
}

// ---------------------------------------------------------------------------
// PromptContextInputs — caller-supplied inputs to buildPromptContext()
// ---------------------------------------------------------------------------

export interface PromptContextInputs {
  /** Workflow row from SQLite. */
  workflow: WorkflowRow;
  /** Current stage configuration (id and run mode). */
  stage: { id: string; run: 'once' | 'per-item' };
  /** Item row from SQLite. Present only in per-item stage phases. */
  item?: ItemRow;
  /** Absolute path to the worktree directory. */
  worktreePath: string;
  /**
   * Absolute path to architecture.md.
   * Defaults to <worktreePath>/architecture.md if not provided.
   */
  architectureMdPath?: string;
  /**
   * Absolute path to progress.md.
   * Defaults to <worktreePath>/progress.md if not provided.
   */
  progressMdPath?: string;
  /**
   * Absolute path to handoff.json.
   * Defaults to <worktreePath>/handoff.json if not provided.
   */
  handoffPath?: string;
  /** Injected git helper. */
  git: GitHelper;
  /**
