// ---------------------------------------------------------------------------
// Internal: apply side effects that are pure SQLite operations
// ---------------------------------------------------------------------------

function applyPendingSideEffects(
  db: SqliteDb,
  sideEffects: readonly string[],
  workflowId: string,
  itemId: string,
  stage: string,
  phase: string,
  now: string,
): void {
  const kind = pendingAttentionKindFromEffects(sideEffects);
