        )
        .all(id) as Array<{
          id: number;
          ts: string;
          workflow_id: string;
          item_id: string | null;
          session_id: string | null;
          stage: string | null;
          phase: string | null;
          attempt: number | null;
          event_type: string;
          level: string;
          message: string;
          extra: string | null;
        }>;

      return reply.send({
        workflowId: id,
        events: events.map((e) => ({
          ...e,
          extra: e.extra ? (() => { try { return JSON.parse(e.extra!); } catch { return e.extra; } })() : null,
        })),
      });
    },
  );

  // GET /api/sessions/:id/log?sinceSeq=&limit=
  // Paged stream-json fetch (D48a). Reads from JSONL file via readLogPage.
  fastify.get(
    '/api/sessions/:id/log',
    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
      const { id } = req.params;
