  // GET /api/workflows/:id/usage?groupBy=feature|phase|profile|session
  // Token aggregates per groupBy dimension.
  fastify.get(
    '/api/workflows/:id/usage',
    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
      const { id } = req.params;
