1	/**
2	 * yoke start — spawn the Yoke pipeline engine.
3	 *
4	 * 1. Loads and validates .yoke.yml via loadConfig (exits non-zero on failure).
5	 * 2. Opens the SQLite database under .yoke/yoke.db; runs forward-only migrations.
6	 * 3. Calls listenServer on 127.0.0.1 at the configured port (default 7777).
7	 * 4. Logs the server URL.
8	 * 5. Writes .yoke/server.json so that yoke status / yoke cancel can discover
9	 *    the running instance.
10	 * 6. Keeps the process alive (the server drives the event loop).
11	 *
12	 * Acceptance criteria:
13	 *   AC: Spawns the pipeline engine and logs the server URL.
14	 *   AC: Exits non-zero if config validation fails.
15	 *   RC: Handles ECONNREFUSED with a clear message (N/A here — start IS the server).
16	 */
17	
18	import fs from 'node:fs';
19	import path from 'node:path';
