 * Broadcast function injected from the server layer.
 * Maps to WsClientRegistry.broadcast().
 */
export type BroadcastFn = (
  workflowId: string,
  sessionId: string | null,
  frameType: ServerFrameType,
  payload: unknown,
) => void;

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const DEFAULT_MAX_PARALLEL = 4;
const DEFAULT_POLL_INTERVAL_MS = 500;
const DEFAULT_GRACE_PERIOD_MS = 10_000;
/** Backoff before re-spawning an awaiting_retry item (ms). */
const RETRY_BACKOFF_MS = 5_000;
const TERMINAL_WF_STATUSES = ['completed', 'abandoned', 'completed_with_blocked'];

// ---------------------------------------------------------------------------
// Internal types
// ---------------------------------------------------------------------------

interface ItemRow {
  id: string;
  workflow_id: string;
  stage_id: string;
  data: string;
  status: string;
  current_phase: string | null;
  depends_on: string | null;
  retry_count: number;
  blocked_reason: string | null;
}

interface WorkflowDbRow {
  id: string;
  name: string;
  status: string;
  current_stage: string | null;
  worktree_path: string | null;
  branch_name: string | null;
}

interface InFlightSession {
  sessionId: string;
  handle: SpawnHandle;
  usage: SessionUsage;
}

type InFlightEntry = InFlightSession | 'pending';

// ---------------------------------------------------------------------------
// SchedulerOpts
// ---------------------------------------------------------------------------

export interface SchedulerOpts {
  db: DbPool;
  config: ResolvedConfig;
  processManager: ProcessManager;
  worktreeManager: WorktreeManager;
  prepostRunner: PrePostRunnerFn;
  assemblePrompt: PromptAssemblerFn;
  broadcast: BroadcastFn;
  /** Poll interval in ms. Default: 500. */
  pollIntervalMs?: number;
  /** Grace period for graceful shutdown drain (ms). Default: 10 000. */
  gracePeriodMs?: number;
  /** Max concurrent sessions. Default: 4. */
  maxParallel?: number;
}

// ---------------------------------------------------------------------------
// Scheduler
// ---------------------------------------------------------------------------

export class Scheduler {
  private readonly db: DbPool;
  private readonly config: ResolvedConfig;
  private readonly processManager: ProcessManager;
  private readonly worktreeManager: WorktreeManager;
  private readonly prepostRunner: PrePostRunnerFn;
  private readonly assemblePromptFn: PromptAssemblerFn;
  private readonly broadcastFn: BroadcastFn;
  private readonly pollIntervalMs: number;
  private readonly gracePeriodMs: number;
  private readonly maxParallel: number;

  /** workflowId populated by start(). */
  workflowId: string | null = null;

  /** Items currently being managed (bootstrapping, spawning, or running). */
  private readonly inFlight = new Map<string, InFlightEntry>();

  /** itemId → timestamp(ms) when the item may next be retried. */
  private readonly retryAfterAt = new Map<string, number>();

  /** itemId → unix seconds when rate-limit window resets. */

// JigProcessManager (exported)
// ---------------------------------------------------------------------------

/**
 * Production ProcessManager. Spawns whatever command + args the caller
 * provides — reads exclusively from SpawnOpts. No string constants here.
 */
export class JigProcessManager implements ProcessManager {
  async spawn(opts: SpawnOpts): Promise<SpawnHandle> {
    const { command, args, cwd, env, promptBuffer, gracePeriodMs = 10_000, logWriter = null } = opts;

    const child = nodeSpawn(command, args, {
      cwd,
      stdio: ['pipe', 'pipe', 'pipe'],
      // Merge caller env over process.env. Never pass undefined as the env
      // option — that is equivalent to inheriting the full environment, which
      // is the intended behaviour here.
      env: env !== undefined ? { ...process.env, ...env } : { ...process.env },
      // detached:true creates a new session + process group for the child
      // (pgid === child.pid on POSIX). This ensures kill(-pgid, signal)

