function probeProcess(pid: number): boolean {
  try {
    process.kill(pid, 0);
    return true;
  } catch (err: unknown) {
    const e = err as NodeJS.ErrnoException;
    // EPERM: process exists but we can't signal it → alive
    if (e.code === 'EPERM') return true;
    // ESRCH: no such process → stale
    return false;
  }
}

